type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function sanitizeKey(key: string): string {
  if (key.includes(".")) {
    return `["${key.replace(/"/g, '\\"')}"]`;
  }
  return key;
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    preserveArrays?: boolean;
  } = {}
): FlattenedObject {
  const { delimiter = ".", maxDepth = Infinity, preserveArrays = true } = options;

  if (maxDepth !== Infinity && (typeof maxDepth !== "number" || maxDepth < 0 || !Number.isFinite(maxDepth))) {
    throw new RangeError(`maxDepth must be a non-negative finite number, got: ${maxDepth}`);
  }

  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(`Input must be a plain object, got: ${Array.isArray(input) ? "array" : typeof input}`);
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (!isPlainObject(current)) {
      if (prefix !== "") {
        result[prefix] = current as Primitive | Array<unknown>;
      }
      return;
    }

    if (seen.has(current as object)) {
      throw new TypeError(`Circular reference detected at key: "${prefix}"`);
    }

    const keys = Object.keys(current as NestedObject);

    if (keys.length === 0) {
      if (prefix !== "") {
        result[prefix] = {} as unknown as Primitive;
      }
      return;
    }

    seen.add(current as object);

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const value = (current as NestedObject)[key];
      const sanitized = sanitizeKey(key);
      const newKey = prefix === "" ? sanitized : `${prefix}${delimiter}${sanitized}`;

      if (Array.isArray(value) && preserveArrays) {
        result[newKey] = value;
      } else if (isPlainObject(value) && depth < maxDepth) {
        recurse(value, newKey, depth + 1);
      } else {
        result[newKey] = value as Primitive | Array<unknown>;
      }
    }

    seen.delete(current as object);
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatRecord = Record<string, Primitive | unknown[]>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  // Treat special built-in objects as leaf values, not traversable
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { prefix?: string; delimiter?: string; maxDepth?: number } = {}
): FlatRecord {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const {
    prefix = "",
    delimiter = ".",
    maxDepth = 100,
  } = options;

  if (typeof delimiter !== "string" || delimiter.length === 0) {
    throw new TypeError("delimiter must be a non-empty string");
  }

  if (!Number.isInteger(maxDepth) || maxDepth < 1) {
    throw new RangeError("maxDepth must be a positive integer");
  }

  const result: FlatRecord = {};
  const seen = new WeakSet<object>();

  function traverse(
    node: Record<string, unknown>,
    currentPrefix: string,
    depth: number
  ): void {
    if (seen.has(node)) {
      throw new Error(
        `Circular reference detected at key: "${currentPrefix}"`
      );
    }

    seen.add(node);

    const keys = Object.keys(node);

    if (keys.length === 0 && currentPrefix !== "") {
      // Preserve empty objects as empty-object sentinel? 
      // Safest: emit them as `{}` so callers know the key existed.
      result[currentPrefix] = {};
    }

    for (const key of keys) {
      // Guard against prototype-pollution keys just in case
      if (key === "__proto__" || key === "constructor" || key === "prototype") {
        continue;
      }

      const fullKey = currentPrefix ? `${currentPrefix}${delimiter}${key}` : key;
      const value: unknown = node[key];

      if (isPlainObject(value) && depth < maxDepth) {
        traverse(value as Record<string, unknown>, fullKey, depth + 1);
      } else {
        // Leaf: primitives, arrays, Dates, RegExps, Functions, class instances, etc.
        result[fullKey] = value as Primitive | unknown[];
      }
    }

    seen.delete(node);
  }

  traverse(input, prefix, 1);

  return result;
}

export default flattenObject;

/**
 * A doubly-linked list node used internally by LRUCache.
 */
interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

/**
 * LRUCache — a generic Least-Recently-Used cache with a fixed capacity.
 *
 * Invariants:
 *  - head.next is the LEAST recently used real node (eviction candidate).
 *  - tail.prev is the MOST recently used real node.
 *  - Every operation that "touches" a node moves it to the tail end.
 *  - Capacity must be a finite positive integer; any violation throws.
 */
export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;

  /** Sentinel head — never holds real data; next → LRU end. */
  private readonly head: Node<T>;
  /** Sentinel tail — never holds real data; prev → MRU end. */
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1 || !Number.isFinite(capacity)) {
      throw new RangeError(
        `LRUCache capacity must be a finite positive integer, got: ${capacity}`
      );
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialise sentinels and wire them together so every insertion
    // can assume prev/next are never null for real nodes.
    this.head = { key: "__head__", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "__tail__", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Returns the cached value for `key`, or `undefined` if absent.
   * Marks the entry as most-recently used on a hit.
   *
   * @throws {TypeError} if key is not a non-empty string.
   */
  get(key: string): T | undefined {
    this.assertKey(key);

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    // Promote to MRU position.
    this.detach(node);
    this.insertBeforeTail(node);

    return node.value;
  }

  /**
   * Inserts or updates the entry for `key`.
   * If the cache is at capacity a new insertion evicts the LRU entry first.
   *
   * @throws {TypeError} if key is not a non-empty string.
   */
  set(key: string, value: T): void {
    this.assertKey(key);

    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update value and promote.
      existing.value = value;
      this.detach(existing);
      this.insertBeforeTail(existing);
      return;
    }

    // Evict LRU entry when at capacity.
    if (this.map.size >= this.capacity) {
      const lru = this.head.next;
      // Defensive: head.next should never be tail unless capacity is broken.
      if (lru === null || lru === this.tail) {
        throw new Error(
          "LRUCache internal invariant violated: no eviction candidate found."
        );
      }
      this.detach(lru);
      this.map.delete(lru.key);
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertBeforeTail(node);
    this.map.set(key, node);
  }

  /** Current number of entries in the cache. */
  get size(): number {
    return this.map.size;
  }

  /** Returns true if the given key exists in the cache (does NOT update recency). */
  has(key: string): boolean {
    this.assertKey(key);
    return this.map.has(key);
  }

  /** Removes a specific entry. Returns true if it existed. */
  delete(key: string): boolean {
    this.assertKey(key);

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.detach(node);
    this.map.delete(key);
    return true;
  }

  /** Removes all entries. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ---------------------------------------------------------------------------
  // Private helpers
  // ---------------------------------------------------------------------------

  /**
   * Removes `node` from wherever it currently sits in the doubly-linked list.
   * Safe only for non-sentinel nodes that are actually in the list.
   */
  private detach(node: Node<T>): void {
    const prev = node.prev;
    const next = node.next;

    if (prev === null || next === null) {
      // This should never happen for a node that is correctly in the list.
      throw new Error(
        `LRUCache internal invariant violated: detach called on node "${node.key}" with null pointer.`
      );
    }

    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  /**
   * Inserts `node` immediately before the tail sentinel (i.e. MRU position).
   */
  private insertBeforeTail(node: Node<T>): void {
    const prev = this.tail.prev;

    if (prev === null) {
      throw new Error(
        "LRUCache internal invariant violated: tail.prev is null."
      );
    }

    prev.next = node;
    node.prev = prev;
    node.next = this.tail;
    this.tail.prev = node;
  }

  /**
   * Validates that a key is a non-empty string.
   * Empty-string keys are rejected because they are almost always a caller bug.
   */
  private assertKey(key: string): void {
    if (typeof key !== "string") {
      throw new TypeError(
        `LRUCache key must be a string, got: ${typeof key}`
      );
    }
    if (key.length === 0) {
      throw new TypeError("LRUCache key must not be an empty string.");
    }
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>; // sentinel: most recently used end
  private readonly tail: Node<T>; // sentinel: least recently used end

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, received: ${capacity}`
      );
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes eliminate null-checks on insert/remove at boundaries
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, received: ${typeof key}`);
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, received: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError(
        "Storing undefined as a cache value is indistinguishable from a cache miss; use null instead"
      );
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertAtFront(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, received: ${typeof key}`);
    }
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, received: ${typeof key}`);
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // --- private helpers ---

  private insertAtFront(node: Node<T>): void {
    // Place node immediately after head sentinel (most-recently-used position)
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null because tail sentinel is always there
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    // Both prev and next are guaranteed non-null for real nodes because
    // sentinels guard both ends
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    // The node immediately before the tail sentinel is the least recently used
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      // Structural invariant violation — should never happen
      throw new Error("LRUCache internal state is corrupt: no evictable node found");
    }

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be greater than 0");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key)!;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        if (item !== null && typeof item === "object" && !Array.isArray(item)) {
          flattenObject(item as NestedObject, key, result);
        } else if (Array.isArray(item)) {
          flattenObject(item as unknown as NestedObject, key, result);
        } else {
          result[key] = item as Primitive;
        }
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type PlainObject = Record<string, unknown>;
type FlatResult = Record<string, Primitive | unknown[]>;

const isPlainObject = (value: unknown): value is PlainObject => {
  if (value === null || typeof value !== "object") return false;
  // Treat Arrays, Dates, RegExp, Map, Set, etc. as leaf nodes
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
};

const flattenRecursive = (
  input: PlainObject,
  prefix: string,
  result: FlatResult,
  visited: WeakSet<object>,
): void => {
  const keys = Object.keys(input);

  if (keys.length === 0) {
    // Empty object: emit the prefix key with an empty object value
    if (prefix !== "") {
      result[prefix] = input as unknown as Primitive;
    }
    return;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    // Sanitise keys that contain dots to avoid silent ambiguity
    const safeKey = key.replace(/\./g, "\\.");
    const newPrefix = prefix === "" ? safeKey : `${prefix}.${safeKey}`;
    const value: unknown = input[key];

    if (isPlainObject(value)) {
      if (visited.has(value as object)) {
        // Circular reference: emit the key with a sentinel rather than looping forever
        result[newPrefix] = "[Circular]";
        continue;
      }
      visited.add(value as object);
      flattenRecursive(value as PlainObject, newPrefix, result, visited);
      visited.delete(value as object);
    } else {
      result[newPrefix] = value as Primitive;
    }
  }
};

export default function flattenObject(input: unknown): FlatResult {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`,
    );
  }

  const result: FlatResult = {};
  const visited = new WeakSet<object>();
  visited.add(input);

  flattenRecursive(input, "", result, visited);

  return result;
}

type PlainObject = Record<string, unknown>;
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  // Accept Object.create(null) and standard plain objects only —
  // reject Date, RegExp, Map, Set, class instances, etc.
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  input: PlainObject | unknown[],
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  if (seen.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at path: "${prefix || "<root>"}"`
    );
  }
  seen.add(input as object);

  const entries: [string, unknown][] = Array.isArray(input)
    ? input.map((v, i) => [String(i), v])
    : Object.keys(input).map((k) => [k, (input as PlainObject)[k]]);

  for (const [key, value] of entries) {
    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const childKeys = Object.keys(value);
      if (childKeys.length === 0) {
        // Preserve empty objects as leaf values — silently dropping keys
        // would be a destructive information loss the caller can't recover from.
        result[flatKey] = value;
      } else {
        flattenInto(value, flatKey, result, seen);
      }
    } else if (Array.isArray(value)) {
      if (value.length === 0) {
        // Same rationale as empty objects above.
        result[flatKey] = value;
      } else {
        flattenInto(value, flatKey, result, seen);
      }
    } else {
      // Primitives (string, number, boolean, null, undefined, bigint, symbol)
      // land here and are stored as-is.
      result[flatKey] = value;
    }
  }

  // Remove after processing so the same object reference is allowed
  // to appear in multiple non-circular branches of the tree.
  seen.delete(input as object);
}

export default function flattenObject(obj: PlainObject): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, got: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flattenInto(obj, "", result, new WeakSet());
  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expression: string, min: number, max: number): number[] {
  const values = new Set<number>();

  const parts = expression.split(",");

  for (const part of parts) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) values.add(i);
      continue;
    }

    if (trimmed.startsWith("*/")) {
      const stepStr = trimmed.slice(2);
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      for (let i = min; i <= max; i += step) values.add(i);
      continue;
    }

    const rangeStepMatch = trimmed.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
    if (rangeStepMatch) {
      const rangeMin = parseInt(rangeStepMatch[1], 10);
      const rangeMax = parseInt(rangeStepMatch[2], 10);
      const step = rangeStepMatch[3] !== undefined ? parseInt(rangeStepMatch[3], 10) : 1;

      if (rangeMin < min || rangeMax > max) {
        throw new Error(
          `Range "${trimmed}" is out of bounds [${min}, ${max}]`
        );
      }
      if (rangeMin > rangeMax) {
        throw new Error(`Invalid range "${trimmed}": start is greater than end`);
      }
      if (step <= 0) {
        throw new Error(`Invalid step value in range "${trimmed}"`);
      }

      for (let i = rangeMin; i <= rangeMax; i += step) values.add(i);
      continue;
    }

    const num = parseInt(trimmed, 10);
    if (isNaN(num) || trimmed !== String(num)) {
      throw new Error(`Invalid cron field value: "${trimmed}"`);
    }
    if (num < min || num > max) {
      throw new Error(`Value ${num} is out of bounds [${min}, ${max}]`);
    }
    values.add(num);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  return {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour),
    dayOfMonth: parseField(dayOfMonthExpr, ...FIELD_RANGES.dayOfMonth),
    month: parseField(monthExpr, ...FIELD_RANGES.month),
    dayOfWeek: parseField(dayOfWeekExpr, ...FIELD_RANGES.dayOfWeek),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function _flatten(
  obj: PlainObject,
  prefix: string,
  ancestors: Set<object>,
  result: PlainObject
): void {
  if (ancestors.has(obj)) {
    if (prefix) result[prefix] = "[Circular]";
    return;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj;
    return;
  }

  ancestors.add(obj);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const newKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      _flatten(value, newKey, ancestors, result);
    } else {
      result[newKey] = value;
    }
  }

  ancestors.delete(obj);
}

export default function flattenObject(input: unknown): PlainObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: PlainObject = {};
  _flatten(input, "", new Set(), result);
  return result;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (oldest) and tail (newest) — never evicted, never returned
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes eliminate null-checks on every splice
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToTail(node);
    return node.value;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToTail(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertBeforeTail(node);
  }

  get size(): number {
    return this.map.size;
  }

  private unlink(node: Node<T>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertBeforeTail(node: Node<T>): void {
    const prev = this.tail.prev!;
    prev.next = node;
    node.prev = prev;
    node.next = this.tail;
    this.tail.prev = node;
  }

  private moveToTail(node: Node<T>): void {
    this.unlink(node);
    this.insertBeforeTail(node);
  }

  private evictLRU(): void {
    const lru = this.head.next!;
    if (lru === this.tail) {
      // Sentinels are adjacent — cache is already empty; nothing to evict
      return;
    }
    this.unlink(lru);
    this.map.delete(lru.key);
  }
}

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof ParsedCron;

const FIELD_CONFIG: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} in "${context}" is out of valid range [${min}, ${max}]`
    );
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (segment === "") {
    throw new SyntaxError("Empty segment encountered");
  }

  // Step expressions: */n  or  a-b/n  or  a/n
  if (segment.includes("/")) {
    const slashIndex = segment.lastIndexOf("/");
    const stepStr = segment.slice(slashIndex + 1);
    const step = parseInt(stepStr, 10);

    if (!Number.isInteger(step) || isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value "${stepStr}" — must be a positive integer`);
    }

    const rangePart = segment.slice(0, slashIndex);
    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2 || dashParts[0] === "" || dashParts[1] === "") {
        throw new SyntaxError(`Invalid range expression "${rangePart}"`);
      }
      rangeMin = parseInt(dashParts[0], 10);
      rangeMax = parseInt(dashParts[1], 10);
      if (isNaN(rangeMin) || isNaN(rangeMax)) {
        throw new SyntaxError(`Non-numeric values in range "${rangePart}"`);
      }
    } else {
      rangeMin = parseInt(rangePart, 10);
      if (isNaN(rangeMin)) {
        throw new SyntaxError(`Non-numeric step base "${rangePart}"`);
      }
      rangeMax = max;
    }

    assertInBounds(rangeMin, min, max, segment);
    assertInBounds(rangeMax, min, max, segment);

    if (rangeMin > rangeMax) {
      throw new RangeError(
        `Range start ${rangeMin} exceeds range end ${rangeMax} in "${segment}"`
      );
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2 || dashParts[0] === "" || dashParts[1] === "") {
      throw new SyntaxError(`Malformed range expression "${segment}"`);
    }
    const rangeMin = parseInt(dashParts[0], 10);
    const rangeMax = parseInt(dashParts[1], 10);
    if (isNaN(rangeMin) || isNaN(rangeMax)) {
      throw new SyntaxError(`Non-numeric values in range "${segment}"`);
    }
    assertInBounds(rangeMin, min, max, segment);
    assertInBounds(rangeMax, min, max, segment);
    if (rangeMin > rangeMax) {
      throw new RangeError(
        `Range start ${rangeMin} exceeds range end ${rangeMax} in "${segment}"`
      );
    }
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i++) {
      values.push(i);
    }
    return values;
  }

  // Single integer
  const value = parseInt(segment, 10);
  if (isNaN(value) || String(value) !== segment.trim()) {
    throw new SyntaxError(`Unrecognised cron token "${segment}"`);
  }
  assertInBounds(value, min, max, segment);
  return [value];
}

function parseField(rawField: string, min: number, max: number): number[] {
  if (rawField == null || rawField.trim() === "") {
    throw new SyntaxError("Cron field must not be empty");
  }

  const segments = rawField.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(
        `Empty element in comma-separated list "${rawField}" — check for stray commas`
      );
    }
    for (const value of parseSegment(trimmed, min, max)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const { min, max } = FIELD_CONFIG[fieldName];
    try {
      result[fieldName] = parseField(rawFields[i], min, max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof RangeError ? RangeError : SyntaxError)(
        `Invalid ${fieldName} field "${rawFields[i]}": ${message}`
      );
    }
  }

  // Canonicalise dayOfWeek: Sunday can be expressed as 0 or 7 — normalise 7 → 0
  const dow = result.dayOfWeek;
  if (dow.includes(7)) {
    const deduplicated = new Set(dow.map((v) => (v === 7 ? 0 : v)));
    result.dayOfWeek = Array.from(deduplicated).sort((a, b) => a - b);
  }

  return result;
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof ParsedCron;

interface FieldConfig {
  readonly name: FieldName;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const;

const INTEGER_RE = /^\d+$/;

function assertInteger(raw: string, context: string): number {
  if (!INTEGER_RE.test(raw)) {
    throw new TypeError(`Expected integer, got "${raw}" in ${context}`);
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] in ${context}`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  min: number,
  max: number,
  context: string
): number[] {
  if (step === 0) {
    throw new RangeError(`Step value cannot be zero in ${context}`);
  }
  if (step < 0) {
    throw new RangeError(`Step value must be positive, got ${step} in ${context}`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in ${context}`
    );
  }
  assertInRange(start, min, max, context);
  assertInRange(end, min, max, context);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseToken(
  token: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const context = `field "${fieldName}"`;

  // Step expression: */n  |  a/n  |  a-b/n
  const slashIdx = token.indexOf("/");
  if (slashIdx !== -1) {
    const rangePart = token.slice(0, slashIdx);
    const stepPart  = token.slice(slashIdx + 1);

    if (rangePart === "" || stepPart === "") {
      throw new SyntaxError(`Malformed step expression "${token}" in ${context}`);
    }

    const step = assertInteger(stepPart, context);

    if (rangePart === "*") {
      return expandRange(min, max, step, min, max, context);
    }

    const dashIdx = rangePart.indexOf("-");
    if (dashIdx !== -1) {
      const start = assertInteger(rangePart.slice(0, dashIdx), context);
      const end   = assertInteger(rangePart.slice(dashIdx + 1), context);
      return expandRange(start, end, step, min, max, context);
    }

    // Single start value with step: treat upper bound as field max
    const start = assertInteger(rangePart, context);
    assertInRange(start, min, max, context);
    return expandRange(start, max, step, min, max, context);
  }

  // Wildcard
  if (token === "*") {
    return expandRange(min, max, 1, min, max, context);
  }

  // Range: a-b
  const dashIdx = token.indexOf("-");
  if (dashIdx !== -1) {
    const start = assertInteger(token.slice(0, dashIdx), context);
    const end   = assertInteger(token.slice(dashIdx + 1), context);
    return expandRange(start, end, 1, min, max, context);
  }

  // Single value
  const value = assertInteger(token, context);
  assertInRange(value, min, max, context);
  return [value];
}

function parseField(
  raw: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (raw.trim() === "") {
    throw new SyntaxError(`Empty field value for "${fieldName}"`);
  }

  const parts = raw.split(",");
  const seen  = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new SyntaxError(
        `Empty token in comma-separated list for field "${fieldName}"`
      );
    }
    for (const v of parseToken(trimmed, min, max, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression cannot be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${fields.length}`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i]!;
    result[name] = parseField(fields[i]!, min, max, name);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix = "",
  visited = new WeakSet<object>(),
): Record<string, Primitive> {
  if (input === null || input === undefined) {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  const obj = input as Record<string, unknown>;

  if (visited.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`,
    );
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    return prefix ? { [prefix]: {} as unknown as Primitive } : {};
  }

  visited.add(obj);

  const result: Record<string, Primitive> = {};

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    if (key === "" || key.includes(".")) {
      throw new TypeError(
        `Key "${key}" contains a dot or is empty, which would produce ambiguous flattened keys.`,
      );
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      const nested = flattenObject(value, fullKey, visited);
      Object.assign(result, nested);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  visited.delete(obj);

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  readonly name: string;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 6, name: "dayOfWeek" },
] as const;

const FIELD_NAMES = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

type FieldName = (typeof FIELD_NAMES)[number];

function parseStrictInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid integer value "${raw}" in ${context}. Only non-negative integers are allowed.`
    );
  }
  const n = Number(trimmed);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new Error(`Value "${raw}" overflows a safe integer in ${context}.`);
  }
  return n;
}

function assertInBounds(n: number, config: FieldConfig, context: string): void {
  if (n < config.min || n > config.max) {
    throw new RangeError(
      `Value ${n} is out of bounds [${config.min}–${config.max}] for field "${config.name}" in "${context}".`
    );
  }
}

function buildRange(start: number, end: number, config: FieldConfig, context: string): number[] {
  assertInBounds(start, config, context);
  assertInBounds(end, config, context);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in "${context}" for field "${config.name}".`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

/**
 * Parses a single (non-comma) cron field token. Handles:
 *   *          wildcard
 *   n          single integer
 *   n-m        range
 *   * /n       step over full range (space intentional in doc — no space in code)
 *   n-m/s      step over range
 *   n/s        step from n to max
 */
function parseSingleToken(token: string, config: FieldConfig): number[] {
  const ctx = `"${token}" (field: ${config.name})`;

  if (token === "") {
    throw new Error(`Empty token encountered in field "${config.name}".`);
  }

  // ── Step expression: anything containing "/" ────────────────────────────
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const rangeStr = token.slice(0, slashIdx);
    const stepStr = token.slice(slashIdx + 1);

    if (stepStr.includes("/")) {
      throw new Error(`Multiple "/" characters in token ${ctx}.`);
    }

    const step = parseStrictInteger(stepStr, ctx);
    if (step === 0) {
      throw new Error(`Step value must be ≥ 1 in ${ctx}.`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangeStr === "*") {
      rangeStart = config.min;
      rangeEnd = config.max;
    } else if (rangeStr.includes("-")) {
      const dashIdx = rangeStr.indexOf("-");
      rangeStart = parseStrictInteger(rangeStr.slice(0, dashIdx), ctx);
      rangeEnd = parseStrictInteger(rangeStr.slice(dashIdx + 1), ctx);
    } else {
      rangeStart = parseStrictInteger(rangeStr, ctx);
      rangeEnd = config.max;
    }

    assertInBounds(rangeStart, config, ctx);
    assertInBounds(rangeEnd, config, ctx);

    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start ${rangeStart} exceeds range end ${rangeEnd} in ${ctx}.`
      );
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  // ── Pure wildcard ────────────────────────────────────────────────────────
  if (token === "*") {
    return buildRange(config.min, config.max, config, token);
  }

  // ── Range: n-m ──────────────────────────────────────────────────────────
  if (token.includes("-")) {
    const dashIdx = token.indexOf("-");
    if (dashIdx === 0) {
      throw new Error(`Leading dash in range token ${ctx}.`);
    }
    const start = parseStrictInteger(token.slice(0, dashIdx), ctx);
    const end = parseStrictInteger(token.slice(dashIdx + 1), ctx);
    return buildRange(start, end, config, token);
  }

  // ── Single integer ───────────────────────────────────────────────────────
  const n = parseStrictInteger(token, ctx);
  assertInBounds(n, config, `"${token}" (field: ${config.name})`);
  return [n];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new Error(`Field "${config.name}" is empty.`);
  }

  // ── Comma-separated list ─────────────────────────────────────────────────
  // Split first so each part can independently be a range, step, or literal.
  const parts = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const stripped = part.trim();
    if (stripped === "") {
      throw new Error(
        `Empty element in comma-separated list for field "${config.name}": "${trimmed}".`
      );
    }
    const expanded = parseSingleToken(stripped, config);
    for (const v of expanded) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

/**
 * Parses a standard 5-field cron expression string into a structured object
 * whose fields contain sorted arrays of all matching integer values.
 *
 * Valid ranges:
 *   minute      0–59
 *   hour        0–23
 *   dayOfMonth  1–31
 *   month       1–12
 *   dayOfWeek   0–6  (0 = Sunday)
 *
 * @throws {Error | RangeError} on malformed input or out-of-range values.
 */
export default function parseCron(expression: unknown): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}.`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty.");
  }

  // Guard against control characters or obviously dangerous input.
  if (/[\x00-\x08\x0b-\x1f\x7f]/.test(trimmed)) {
    throw new Error("Cron expression contains invalid control characters.");
  }

  const fields = trimmed.split(/[ \t]+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 space-separated fields, but found ${fields.length}: "${expression}".`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i] as FieldName;
    const config = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], config);
  }

  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, min: number, max: number): number[] {
  const allValues = range(min, max);

  if (expr === "*") return allValues;

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${expr}`);
    return allValues.filter((v) => (v - min) % step === 0);
  }

  if (expr.includes(",")) {
    const parts = expr.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) values.add(v);
    }
    return [...values].sort((a, b) => a - b);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${expr}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds: ${expr} (valid: ${min}-${max})`);
    return range(start, end);
  }

  if (expr.includes("/")) {
    const [rangeOrStar, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${expr}`);
    let base: number[];
    if (rangeOrStar === "*") {
      base = allValues;
    } else if (rangeOrStar.includes("-")) {
      const [s, e] = rangeOrStar.split("-").map(Number);
      if (s < min || e > max || s > e) throw new Error(`Range out of bounds: ${expr}`);
      base = range(s, e);
    } else {
      const start = parseInt(rangeOrStar, 10);
      if (isNaN(start) || start < min || start > max)
        throw new Error(`Invalid start: ${expr}`);
      base = range(start, max);
    }
    return base.filter((v, i) => i % step === 0);
  }

  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: ${expr}`);
  if (num < min || num > max)
    throw new Error(`Value ${num} out of range (${min}-${max})`);
  return [num];
}

function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string")
    throw new Error("Cron expression must be a non-empty string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronResult;
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(exprs[i], min, max);
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    arrayHandling?: "stringify" | "expand" | "skip";
  } = {}
): FlatObject {
  const delimiter = options.delimiter ?? ".";
  const maxDepth = options.maxDepth ?? 64;
  const arrayHandling = options.arrayHandling ?? "expand";

  if (delimiter === "") {
    throw new Error("Delimiter must be a non-empty string.");
  }
  if (maxDepth < 1 || !Number.isInteger(maxDepth)) {
    throw new Error("maxDepth must be a positive integer.");
  }
  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object, received: ${input === null ? "null" : typeof input}`
    );
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      // Treat anything beyond maxDepth as a terminal leaf — stringify it
      result[prefix] = String(current);
      return;
    }

    if (Array.isArray(current)) {
      if (arrayHandling === "skip") {
        // Drop arrays entirely — don't emit anything for this key
        return;
      }
      if (arrayHandling === "stringify") {
        result[prefix] = JSON.stringify(current);
        return;
      }
      // arrayHandling === "expand": treat indices as keys
      if (seen.has(current)) {
        result[prefix] = "[Circular]";
        return;
      }
      seen.add(current);
      if (current.length === 0) {
        // Preserve empty arrays as a distinct leaf value
        result[prefix] = "[]";
        seen.delete(current);
        return;
      }
      for (let i = 0; i < current.length; i++) {
        const childKey = prefix === "" ? String(i) : `${prefix}${delimiter}${i}`;
        recurse(current[i], childKey, depth + 1);
      }
      seen.delete(current);
      return;
    }

    if (isPlainObject(current)) {
      if (seen.has(current as object)) {
        result[prefix] = "[Circular]";
        return;
      }
      seen.add(current as object);
      const keys = Object.keys(current as NestedObject);
      if (keys.length === 0) {
        // Preserve empty objects — only emit if we have a prefix to anchor to
        if (prefix !== "") {
          result[prefix] = "{}";
        }
        seen.delete(current as object);
        return;
      }
      for (const key of keys) {
        if (!Object.prototype.hasOwnProperty.call(current, key)) continue;
        const childKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
        recurse((current as NestedObject)[key], childKey, depth + 1);
      }
      seen.delete(current as object);
      return;
    }

    // Terminal leaf: number, string, boolean, null, undefined, bigint, symbol
    if (current === undefined) {
      // Undefined values are explicit signals — preserve them
      result[prefix] = undefined;
      return;
    }
    if (typeof current === "bigint" || typeof current === "symbol") {
      result[prefix] = current.toString();
      return;
    }
    if (
      typeof current === "string" ||
      typeof current === "number" ||
      typeof current === "boolean" ||
      current === null
    ) {
      // Guard against NaN / Infinity slipping through unnoticed
      if (typeof current === "number" && !isFinite(current)) {
        result[prefix] = String(current); // "NaN" | "Infinity" | "-Infinity"
        return;
      }
      result[prefix] = current;
      return;
    }
    // Fallback for anything exotic (functions, class instances, etc.)
    result[prefix] = String(current);
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) {
      return undefined;
    }
    // Non-null assertion is safe: has() just confirmed the key exists
    const value = this.cache.get(key) as T;
    // Promote to most-recently-used by reinserting at the end
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      // Updating an existing key must not trigger eviction,
      // but must still promote it to most-recently-used
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Map iteration order is insertion order, so the first key is the LRU
      const lruKey = this.cache.keys().next().value;
      // Guard: next().value is undefined only on an empty map,
      // which cannot happen here (size >= capacity >= 1), but be safe
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }
    this.cache.set(key, value);
  }

  /** Current number of entries — useful for introspection and testing. */
  get size(): number {
    return this.cache.size;
  }
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronFields;
  min: number;
  max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

const EXPECTED_FIELD_COUNT = 5;

function isInteger(value: number): boolean {
  return Number.isInteger(value);
}

function clampCheck(value: number, min: number, max: number, fieldName: string): number {
  if (!isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Invalid value ${value} for field "${fieldName}": must be an integer between ${min} and ${max}.`
    );
  }
  return value;
}

function parseNumber(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(
      `Invalid numeric token "${trimmed}" in field "${fieldName}": only digits are allowed.`
    );
  }
  return parseInt(trimmed, 10);
}

function expandRange(start: number, end: number, fieldName: string, min: number, max: number): number[] {
  if (start > end) {
    throw new RangeError(
      `Invalid range ${start}-${end} in field "${fieldName}": start must be <= end.`
    );
  }
  clampCheck(start, min, max, fieldName);
  clampCheck(end, min, max, fieldName);
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function expandStep(rangeStr: string, step: number, fieldName: string, min: number, max: number): number[] {
  if (!isInteger(step) || step < 1) {
    throw new RangeError(
      `Invalid step value ${step} in field "${fieldName}": step must be a positive integer.`
    );
  }

  let start: number;
  let end: number;

  if (rangeStr === "*") {
    start = min;
    end = max;
  } else if (/^\d+$/.test(rangeStr.trim())) {
    start = parseNumber(rangeStr, fieldName);
    clampCheck(start, min, max, fieldName);
    end = max;
  } else if (/^\d+-\d+$/.test(rangeStr.trim())) {
    const [startStr, endStr] = rangeStr.trim().split("-");
    start = parseNumber(startStr, fieldName);
    end   = parseNumber(endStr,   fieldName);
    clampCheck(start, min, max, fieldName);
    clampCheck(end,   min, max, fieldName);
    if (start > end) {
      throw new RangeError(
        `Invalid range ${start}-${end} in step expression for field "${fieldName}": start must be <= end.`
      );
    }
  } else {
    throw new SyntaxError(
      `Invalid range portion "${rangeStr}" in step expression for field "${fieldName}".`
    );
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseToken(token: string, fieldName: string, min: number, max: number): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty token encountered in field "${fieldName}".`);
  }

  // Step expression: e.g. "*/15" or "1-5/2" or "0/5"
  if (trimmed.includes("/")) {
    const slashCount = (trimmed.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(
        `Invalid step expression "${trimmed}" in field "${fieldName}": exactly one "/" is allowed.`
      );
    }
    const slashIndex = trimmed.indexOf("/");
    const rangePart  = trimmed.slice(0, slashIndex);
    const stepPart   = trimmed.slice(slashIndex + 1);

    if (rangePart === "") {
      throw new SyntaxError(
        `Missing range before "/" in step expression "${trimmed}" for field "${fieldName}".`
      );
    }
    if (stepPart === "" || !/^\d+$/.test(stepPart)) {
      throw new SyntaxError(
        `Invalid step "${stepPart}" in expression "${trimmed}" for field "${fieldName}": must be a positive integer.`
      );
    }

    const step = parseInt(stepPart, 10);
    return expandStep(rangePart, step, fieldName, min, max);
  }

  // Wildcard: "*"
  if (trimmed === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range expression: e.g. "1-5"
  if (trimmed.includes("-")) {
    const dashCount = (trimmed.match(/-/g) ?? []).length;
    if (dashCount !== 1) {
      throw new SyntaxError(
        `Invalid range expression "${trimmed}" in field "${fieldName}": exactly one "-" is allowed.`
      );
    }
    const dashIndex = trimmed.indexOf("-");
    const startStr  = trimmed.slice(0, dashIndex);
    const endStr    = trimmed.slice(dashIndex + 1);

    if (startStr === "" || endStr === "") {
      throw new SyntaxError(
        `Invalid range "${trimmed}" in field "${fieldName}": both start and end must be specified.`
      );
    }

    const start = parseNumber(startStr, fieldName);
    const end   = parseNumber(endStr,   fieldName);
    return expandRange(start, end, fieldName, min, max);
  }

  // Plain number
  const value = parseNumber(trimmed, fieldName);
  clampCheck(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string for field "${name}", got ${typeof expression}.`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Field "${name}" is empty.`);
  }

  const parts = trimmed.split(",");
  if (parts.length === 0) {
    throw new SyntaxError(`Field "${name}" produced no tokens after splitting.`);
  }

  const valueSet = new Set<number>();

  for (const part of parts) {
    const expanded = parseToken(part, name, min, max);
    for (const v of expanded) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}.`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("parseCron received an empty expression.");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== EXPECTED_FIELD_COUNT) {
    throw new SyntaxError(
      `Invalid cron expression: expected ${EXPECTED_FIELD_COUNT} fields, got ${fields.length}. ` +
      `Expression: "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(fields[i], config);
  }

  return result;
}

export default parseCron;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (MRU side) and tail (LRU side) — never evicted, simplifies pointer logic
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 1) {
      throw new RangeError(`Capacity must be at least 1, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels carry no meaningful key/value — cast is intentional
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Storing undefined as a cache value is not allowed; use null instead");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }
    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }
    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Private helpers ──────────────────────────────────────────────────────────

  private removeNode(node: Node<T>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Guard: lru should never be the head sentinel while map.size > 0, but be safe
    if (lru === null || lru === this.head) {
      return;
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

interface DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null;
  next: DLinkedNode<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLinkedNode<T>>;
  // Sentinel head (MRU side) and tail (LRU side) — never hold real data
  private readonly head: DLinkedNode<T>;
  private readonly tail: DLinkedNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 1) {
      throw new RangeError(`Capacity must be at least 1, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels simplify boundary conditions — no null-checks on insert/remove
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    // Promote to MRU position
    this.detach(node);
    this.insertAfterHead(node);

    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use null to represent absence");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update value and promote to MRU
      existing.value = value;
      this.detach(existing);
      this.insertAfterHead(existing);
      return;
    }

    // Evict LRU before inserting if at capacity
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;
      if (lru === null || lru === this.head) {
        // Should be structurally impossible given capacity >= 1, but guard anyway
        throw new Error("Invariant violation: cache is full but no evictable node found");
      }
      this.detach(lru);
      this.map.delete(lru.key);
    }

    const node: DLinkedNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAfterHead(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.detach(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Private helpers ────────────────────────────────────────────────────────

  private detach(node: DLinkedNode<T>): void {
    const prev = node.prev;
    const next = node.next;

    if (prev === null || next === null) {
      throw new Error("Invariant violation: attempted to detach an unlinked node");
    }

    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertAfterHead(node: DLinkedNode<T>): void {
    const after = this.head.next;

    if (after === null) {
      throw new Error("Invariant violation: head sentinel has no next pointer");
    }

    node.prev = this.head;
    node.next = after;
    this.head.next = node;
    after.prev = node;
  }
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  }, // 0 and 7 are both Sunday (normalized later)
] as const;

function assertFiniteInteger(value: number, context: string): void {
  if (!Number.isFinite(value) || !Number.isInteger(value)) {
    throw new Error(`Invalid non-integer value in ${context}: "${value}"`);
  }
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  assertFiniteInteger(value, context);
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} in ${context} is out of allowed range [${min}, ${max}]`
    );
  }
}

function parseNumericString(raw: string, context: string): number {
  if (raw === "" || raw.trim() !== raw) {
    throw new Error(`Invalid numeric string "${raw}" in ${context}`);
  }
  const n = Number(raw);
  if (Number.isNaN(n)) {
    throw new Error(`Non-numeric value "${raw}" in ${context}`);
  }
  return n;
}

function rangeArray(start: number, end: number): number[] {
  const arr: number[] = [];
  for (let v = start; v <= end; v++) {
    arr.push(v);
  }
  return arr;
}

function stepArray(rangeMin: number, rangeMax: number, step: number): number[] {
  const arr: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    arr.push(v);
  }
  return arr;
}

function parseToken(
  token: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const ctx = `field "${fieldName}", token "${token}"`;

  if (token === "") {
    throw new Error(`Empty token encountered in field "${fieldName}"`);
  }

  // Step expression: base/step
  const slashIdx = token.indexOf("/");
  if (slashIdx !== -1) {
    const baseStr = token.slice(0, slashIdx);
    const stepStr = token.slice(slashIdx + 1);

    if (baseStr === "" || stepStr === "") {
      throw new Error(`Malformed step expression in ${ctx}`);
    }

    const step = parseNumericString(stepStr, ctx);
    assertFiniteInteger(step, ctx);
    if (step <= 0) {
      throw new RangeError(`Step value must be a positive integer in ${ctx}, got ${step}`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (baseStr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else {
      const dashIdx = baseStr.indexOf("-");
      if (dashIdx === -1) {
        // Single start value: value/step means start..max/step
        rangeMin = parseNumericString(baseStr, ctx);
        assertInRange(rangeMin, min, max, ctx);
        rangeMax = max;
      } else {
        const startStr = baseStr.slice(0, dashIdx);
        const endStr   = baseStr.slice(dashIdx + 1);
        if (startStr === "" || endStr === "") {
          throw new Error(`Malformed range in step base of ${ctx}`);
        }
        rangeMin = parseNumericString(startStr, ctx);
        rangeMax = parseNumericString(endStr, ctx);
        assertInRange(rangeMin, min, max, ctx);
        assertInRange(rangeMax, min, max, ctx);
        if (rangeMin > rangeMax) {
          throw new RangeError(
            `Range start ${rangeMin} exceeds range end ${rangeMax} in ${ctx}`
          );
        }
      }
    }

    return stepArray(rangeMin, rangeMax, step);
  }

  // Wildcard
  if (token === "*") {
    return rangeArray(min, max);
  }

  // Range expression: start-end
  // Use indexOf to locate the first dash, but guard against leading dash (negative numbers are invalid)
  const dashIdx = token.indexOf("-");
  if (dashIdx > 0) {
    const startStr = token.slice(0, dashIdx);
    const endStr   = token.slice(dashIdx + 1);

    if (startStr === "" || endStr === "") {
      throw new Error(`Malformed range expression in ${ctx}`);
    }
    // Guard against a second dash indicating a negative end value
    if (endStr.includes("-")) {
      throw new Error(`Unexpected dash in range end of ${ctx}`);
    }

    const start = parseNumericString(startStr, ctx);
    const end   = parseNumericString(endStr, ctx);
    assertInRange(start, min, max, ctx);
    assertInRange(end, min, max, ctx);

    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds range end ${end} in ${ctx}`
      );
    }

    return rangeArray(start, end);
  }

  // Plain integer
  const n = parseNumericString(token, ctx);
  assertInRange(n, min, max, ctx);
  return [n];
}

function parseField(
  raw: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (raw === "" || raw.trim() === "") {
    throw new Error(`Field "${fieldName}" is empty or blank`);
  }

  const tokens = raw.split(",");

  if (tokens.length === 0) {
    throw new Error(`Field "${fieldName}" produced no tokens after splitting`);
  }

  const valueSet = new Set<number>();

  for (const token of tokens) {
    const trimmed = token.trim();
    if (trimmed === "") {
      throw new Error(
        `Empty token found in comma-separated list of field "${fieldName}" (value: "${raw}")`
      );
    }
    const values = parseToken(trimmed, min, max, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields ` +
      `(minute hour dayOfMonth month dayOfWeek), got ${parts.length}: "${expression}"`
    );
  }

  const result: CronFields = {
    minute:     [],
    hour:       [],
    dayOfMonth: [],
    month:      [],
    dayOfWeek:  [],
  };

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(parts[i], min, max, name);
  }

  // Normalize dayOfWeek: both 0 and 7 represent Sunday in standard cron.
  // Collapse 7 → 0 so consumers always see 0 for Sunday.
  if (result.dayOfWeek.includes(7)) {
    const normalized = new Set(result.dayOfWeek.map(d => (d === 7 ? 0 : d)));
    result.dayOfWeek = Array.from(normalized).sort((a, b) => a - b);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object"
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_ORDER: ReadonlyArray<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

const FIELD_RANGES: Readonly<Record<keyof CronFields, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

function isNonNegativeInteger(s: string): boolean {
  return s.length > 0 && /^\d+$/.test(s);
}

function expandRange(
  from: number,
  to: number,
  step: number,
  fieldMin: number,
  fieldMax: number,
): number[] {
  if (step <= 0) {
    throw new Error(`Step must be >= 1, got ${step}`);
  }
  if (from < fieldMin || from > fieldMax) {
    throw new Error(`Value ${from} out of range [${fieldMin}, ${fieldMax}]`);
  }
  if (to < fieldMin || to > fieldMax) {
    throw new Error(`Value ${to} out of range [${fieldMin}, ${fieldMax}]`);
  }
  if (from > to) {
    throw new Error(`Range start ${from} exceeds range end ${to}`);
  }

  const values: number[] = [];
  for (let i = from; i <= to; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (segment.length === 0) {
    throw new Error("Empty segment");
  }

  const slashIdx = segment.indexOf("/");
  let base: string;
  let step: number;

  if (slashIdx !== -1) {
    base = segment.slice(0, slashIdx);
    const stepPart = segment.slice(slashIdx + 1);

    // Guard against double-slash or empty step like "*//" or "1/"
    if (!isNonNegativeInteger(stepPart)) {
      throw new Error(`Invalid step "${stepPart}" in segment "${segment}"`);
    }
    step = parseInt(stepPart, 10);
    if (step === 0) {
      throw new Error(`Step cannot be zero in segment "${segment}"`);
    }
  } else {
    base = segment;
    step = 1;
  }

  // Wildcard: * or */n
  if (base === "*") {
    return expandRange(min, max, step, min, max);
  }

  // Range: n-m or n-m/s
  const dashIdx = base.indexOf("-");
  if (dashIdx !== -1) {
    const fromPart = base.slice(0, dashIdx);
    const toPart = base.slice(dashIdx + 1);

    // Guard against leading-dash or empty parts: "-5", "5-", "5-3-1"
    if (!isNonNegativeInteger(fromPart) || !isNonNegativeInteger(toPart)) {
      throw new Error(`Invalid range "${base}" in segment "${segment}"`);
    }

    const from = parseInt(fromPart, 10);
    const to = parseInt(toPart, 10);
    return expandRange(from, to, step, min, max);
  }

  // Plain number or number/step (e.g. "5/15" = start at 5, every 15 until max)
  if (!isNonNegativeInteger(base)) {
    throw new Error(`Invalid value "${base}" in segment "${segment}"`);
  }

  const value = parseInt(base, 10);
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }

  if (slashIdx !== -1) {
    // "5/15" → start at 5, step to max
    return expandRange(value, max, step, min, max);
  }

  return [value];
}

function parseField(raw: string, min: number, max: number): number[] {
  // Guard against empty or whitespace-only field
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new Error("Field is empty or whitespace");
  }

  const segments = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const s = segment.trim();
    if (s.length === 0) {
      throw new Error(`Empty segment found in field "${raw}" — trailing or double comma?`);
    }
    const values = parseSegment(s, min, max);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  if (valueSet.size === 0) {
    throw new Error(`Field "${raw}" produced no values`);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression is empty");
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${rawFields.length}: "${expression}"`,
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    const { min, max } = FIELD_RANGES[name];

    try {
      result[name] = parseField(rawFields[i], min, max);
    } catch (err) {
      // Re-throw with field context so the caller knows exactly what broke
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid ${name} field "${rawFields[i]}": ${message}`);
    }
  }

  return result;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>; // sentinel: most recently used end
  private readonly tail: Node<T>; // sentinel: least recently used end

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${typeof capacity}`);
    }
    if (capacity < 1) {
      throw new RangeError(`Capacity must be at least 1, got: ${capacity}`);
    }
    if (!Number.isFinite(capacity)) {
      throw new RangeError(`Capacity must be a finite number, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes eliminate null-checks on head/tail operations
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (key === null || key === undefined) {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (key === null || key === undefined) {
      throw new TypeError(`Cache key must be a non-null string, got: ${key}`);
    }
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (key === null || key === undefined) {
      return false;
    }
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (key === null || key === undefined) {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;

    // head.next is always non-null because tail sentinel always exists
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    // Sentinels guarantee prev/next are never null for real nodes
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;

    // Sanity guard: tail.prev should never be the head sentinel when map.size > 0
    if (lru === null || lru === this.head) {
      // Structural invariant violated — clear and recover rather than silently corrupt
      this.clear();
      throw new Error("LRUCache internal structure corrupted during eviction");
    }

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    // Map preserves insertion order and allows O(1) reordering via delete+re-insert
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    if (!this.cache.has(key)) {
      return undefined;
    }

    // Promote to most-recently-used by reinserting at end
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError(
        "Storing undefined as a cache value is not permitted; use delete() to remove entries"
      );
    }

    if (this.cache.has(key)) {
      // Update existing entry and promote to most-recently-used
      this.cache.delete(key);
      this.cache.set(key, value);
      return;
    }

    // Evict least-recently-used (first entry in Map) before inserting
    if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }
    return this.cache.delete(key);
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }
    return this.cache.has(key);
  }

  clear(): void {
    this.cache.clear();
  }

  get size(): number {
    return this.cache.size;
  }

  get maxCapacity(): number {
    return this.capacity;
  }
}

export default LRUCache;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
