type Primitive = string | number | boolean | null | undefined;

interface NestedObject {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
}

type FlatObject = Record<string, Primitive>;

function flattenObject(
  obj: NestedObject | Record<string, unknown>,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as Record<string, unknown>, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = (obj as Record<string, unknown>)[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as Record<string, unknown>, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

// dayOfWeek max is 7 to allow the common Sunday alias; normalized to 0 in output
const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in expression "${context}"`
    );
  }
}

function parseToken(
  token: string,
  min: number,
  max: number,
  context: string
): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty token in cron expression "${context}"`);
  }

  // Step: */n  or  start/n  or  start-end/n
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.lastIndexOf("/");
    const rangePart = trimmed.slice(0, slashIndex);
    const stepStr = trimmed.slice(slashIndex + 1);

    if (rangePart === "" || stepStr === "") {
      throw new SyntaxError(`Malformed step expression "${trimmed}"`);
    }

    const step = Number(stepStr);
    if (!Number.isInteger(step) || isNaN(step)) {
      throw new SyntaxError(`Non-integer step value in "${trimmed}"`);
    }
    if (step <= 0) {
      throw new RangeError(
        `Step value must be a positive integer in "${trimmed}"`
      );
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const dashIndex = rangePart.indexOf("-");
      const startStr = rangePart.slice(0, dashIndex);
      const endStr = rangePart.slice(dashIndex + 1);
      start = Number(startStr);
      end = Number(endStr);
      if (!Number.isInteger(start) || isNaN(start)) {
        throw new SyntaxError(`Non-integer range start in "${trimmed}"`);
      }
      if (!Number.isInteger(end) || isNaN(end)) {
        throw new SyntaxError(`Non-integer range end in "${trimmed}"`);
      }
      assertInRange(start, min, max, context);
      assertInRange(end, min, max, context);
      if (start > end) {
        throw new RangeError(
          `Range start ${start} exceeds end ${end} in "${trimmed}"`
        );
      }
    } else {
      start = Number(rangePart);
      if (!Number.isInteger(start) || isNaN(start)) {
        throw new SyntaxError(`Non-integer step base in "${trimmed}"`);
      }
      assertInRange(start, min, max, context);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (trimmed === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: n-m
  if (trimmed.includes("-")) {
    const dashIndex = trimmed.indexOf("-");
    const startStr = trimmed.slice(0, dashIndex);
    const endStr = trimmed.slice(dashIndex + 1);

    if (startStr === "" || endStr === "") {
      throw new SyntaxError(`Malformed range "${trimmed}"`);
    }

    const start = Number(startStr);
    const end = Number(endStr);

    if (!Number.isInteger(start) || isNaN(start)) {
      throw new SyntaxError(`Non-integer range start in "${trimmed}"`);
    }
    if (!Number.isInteger(end) || isNaN(end)) {
      throw new SyntaxError(`Non-integer range end in "${trimmed}"`);
    }

    assertInRange(start, min, max, context);
    assertInRange(end, min, max, context);

    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in "${trimmed}"`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Single value
  const value = Number(trimmed);
  if (!Number.isInteger(value) || isNaN(value)) {
    throw new SyntaxError(
      `Non-integer value "${trimmed}" in cron expression "${context}"`
    );
  }
  assertInRange(value, min, max, context);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const parts = expression.split(",");

  if (parts.length === 0 || (parts.length === 1 && parts[0].trim() === "")) {
    throw new SyntaxError(`Empty field value for "${field}"`);
  }

  const valueSet = new Set<number>();

  for (const part of parts) {
    const tokens = parseToken(part, min, max, `${field}:${expression}`);
    for (const v of tokens) {
      // Normalize Sunday alias: dayOfWeek 7 → 0
      valueSet.add(field === "dayOfWeek" && v === 7 ? 0 : v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on whitespace; reject tabs/unusual separators by normalizing first
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const raw = fields[i];

    if (raw === undefined || raw === "") {
      throw new SyntaxError(`Missing value for field "${field}"`);
    }

    result[field] = parseField(raw, field);
  }

  return result;
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("Capacity must be a positive integer");
    }
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key)!;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlattenedObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${Array.isArray(input) ? "array" : typeof input}`
    );
  }

  const result: FlattenedObject = {};

  function recurse(
    current: Record<string, unknown>,
    prefix: string,
    depth: number
  ): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or overly nested object.`
      );
    }

    const keys = Object.keys(current);

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
      const value = current[key];

      if (isPlainObject(value)) {
        const nestedKeys = Object.keys(value);
        if (nestedKeys.length === 0) {
          // Empty object: store as-is with empty object sentinel? 
          // Safest: skip — no leaf value to represent. Caller can detect absence.
          // We store nothing to avoid misleading primitive coercions.
          continue;
        }
        recurse(value, fullKey, depth + 1);
      } else if (Array.isArray(value)) {
        // Arrays are not plain objects; treat as leaf to avoid silently
        // mangling array structure into "a.0", "a.1" which loses type info.
        // Cast to unknown first to satisfy strict assignment.
        result[fullKey] = value as unknown as Primitive;
      } else if (typeof value === "function" || typeof value === "symbol") {
        // Functions and symbols are not serialisable primitives — skip them
        // rather than storing "[object Function]" noise.
        continue;
      } else {
        result[fullKey] = value as Primitive;
      }
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  result: FlattenedObject = {},
  visited = new WeakSet<object>()
): FlattenedObject {
  if (input === null || input === undefined) {
    return result;
  }

  if (typeof input !== "object") {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${typeof input}`
    );
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      "flattenObject expects a plain object (not an Array, Date, Map, etc.)"
    );
  }

  if (visited.has(input as object)) {
    throw new Error(
      `Circular reference detected at path: "${prefix || "(root)"}"`
    );
  }

  visited.add(input as object);

  const keys = Object.keys(input as object);

  if (keys.length === 0 && prefix !== "") {
    // Empty nested object — store as empty object marker? Convention: skip it.
    // Remove from visited before returning to allow the same empty obj elsewhere.
    visited.delete(input as object);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const sanitizedKey = key.replace(/\./g, "\\.");
    const fullKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = (input as Record<string, unknown>)[key];

    if (isPlainObject(value)) {
      flattenObject(value, fullKey, result, visited);
    } else if (Array.isArray(value)) {
      for (let i = 0; i < value.length; i++) {
        const element = value[i];
        const arrayKey = `${fullKey}[${i}]`;
        if (isPlainObject(element)) {
          flattenObject(element, arrayKey, result, visited);
        } else {
          result[arrayKey] = element as Primitive;
        }
      }
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  visited.delete(input as object);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { delimiter?: string; maxDepth?: number } = {}
): FlatObject {
  const { delimiter = ".", maxDepth = Infinity } = options;

  if (delimiter === "") {
    throw new Error("Delimiter must be a non-empty string");
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object, got ${input === null ? "null" : typeof input}`
    );
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (!isPlainObject(current)) {
      result[prefix] = current as Primitive | unknown[];
      return;
    }

    if (seen.has(current as object)) {
      throw new Error(
        `Circular reference detected at key "${prefix}"`
      );
    }

    const keys = Object.keys(current as object);

    if (keys.length === 0 || depth >= maxDepth) {
      if (prefix !== "") {
        result[prefix] = current as unknown as Primitive;
      }
      return;
    }

    seen.add(current as object);

    for (const key of keys) {
      if (key === "") {
        // Preserve empty-string keys with a bracketed notation to avoid
        // ambiguity when joined with the delimiter.
        const newKey = prefix === "" ? '[""]' : `${prefix}${delimiter}[""]`;
        const value = (current as NestedObject)[key];
        if (isPlainObject(value) && depth + 1 < maxDepth) {
          recurse(value, newKey, depth + 1);
        } else {
          result[newKey] = value as Primitive | unknown[];
        }
        continue;
      }

      const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
      const value = (current as NestedObject)[key];

      if (isPlainObject(value)) {
        recurse(value, newKey, depth + 1);
      } else {
        result[newKey] = value as Primitive | unknown[];
      }
    }

    seen.delete(current as object);
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlattenedObject = {},
  seen: WeakSet<object> = new WeakSet()
): FlattenedObject {
  if (!isPlainObject(input) && !Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  const obj = input as Record<string, unknown>;

  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }
  seen.add(obj);

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    if (prefix !== "") {
      result[prefix] = Array.isArray(obj) ? ([] as unknown as Primitive) : ({} as unknown as Primitive);
    }
    seen.delete(obj);
    return result;
  }

  for (const [key, value] of entries) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value) || Array.isArray(value)) {
      flattenObject(value, flatKey, result, seen);
    } else {
      result[flatKey] = value as Primitive;
    }
  }

  seen.delete(obj);
  return result;
}

export default flattenObject;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (MRU side) and tail (LRU side) — avoids null checks on every operation
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`capacity must be an integer, received: ${capacity}`);
    }
    // Clamp to 0 so a zero/negative capacity cache is valid but never stores anything
    this.capacity = Math.max(0, capacity);
    this.map = new Map();

    // Sentinels carry no real data; cast satisfies the type without polluting the interface
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    // Promote to MRU position
    this.detach(node);
    this.insertAfterHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache: silently accept writes but never store
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update in-place and promote; no eviction needed — size is unchanged
      existing.value = value;
      this.detach(existing);
      this.insertAfterHead(existing);
      return;
    }

    // Evict LRU entry before inserting to avoid exceeding capacity
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;
      // Guard: only null when the list has only sentinels (i.e., capacity is 0,
      // already handled above), but be defensive anyway
      if (lru !== null && lru !== this.head) {
        this.detach(lru);
        this.map.delete(lru.key);
      }
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAfterHead(node);
  }

  get size(): number {
    return this.map.size;
  }

  // ── Private helpers ────────────────────────────────────────────────────────

  private detach(node: Node<T>): void {
    const { prev, next } = node;
    // Both prev and next are always non-null for a node that is in the list
    // (sentinels bookend it), but guard defensively
    if (prev !== null) prev.next = next;
    if (next !== null) next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertAfterHead(node: Node<T>): void {
    const after = this.head.next!; // always non-null: at minimum points to tail sentinel
    node.prev = this.head;
    node.next = after;
    this.head.next = node;
    after.prev = node;
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (most-recently-used side) and tail (least-recently-used side)
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 0) {
      throw new RangeError(`Capacity must be >= 0, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes eliminate null-checks on every insertion/removal
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    // Promote to most-recently-used position
    this.detach(node);
    this.insertAfterHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache stores nothing — every set is a no-op
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      // Update in place and promote; no eviction needed
      existing.value = value;
      this.detach(existing);
      this.insertAfterHead(existing);
      return;
    }

    // Evict least-recently-used entry before inserting when at capacity
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;
      // Guard against an empty list (sentinels adjacent) — should never
      // happen given capacity >= 1 and map.size >= capacity, but be safe
      if (lru === null || lru === this.head) {
        throw new Error("Invariant violation: cache is at capacity but linked list is empty");
      }
      this.detach(lru);
      this.map.delete(lru.key);
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertAfterHead(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  private detach(node: Node<T>): void {
    const { prev, next } = node;
    // These should never be null for non-sentinel nodes, but guard anyway
    if (prev === null || next === null) {
      throw new Error(`Invariant violation: attempted to detach an unlinked node (key="${node.key}")`);
    }
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertAfterHead(node: Node<T>): void {
    const after = this.head.next;
    if (after === null) {
      throw new Error("Invariant violation: head.next is null — sentinel tail is missing");
    }
    node.prev = this.head;
    node.next = after;
    this.head.next = node;
    after.prev = node;
  }
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandField(expression: string, min: number, max: number): number[] {
  const allValues = () => Array.from({ length: max - min + 1 }, (_, i) => i + min);

  const parseSegment = (segment: string): number[] => {
    if (segment === "*") {
      return allValues();
    }

    if (segment.startsWith("*/")) {
      const step = parseInt(segment.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in segment: "${segment}"`);
      }
      return allValues().filter((v) => (v - min) % step === 0);
    }

    if (segment.includes("/")) {
      const [rangePart, stepPart] = segment.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in segment: "${segment}"`);
      }
      let rangeMin = min;
      let rangeMax = max;
      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [rMin, rMax] = rangePart.split("-").map((n) => parseInt(n, 10));
          if (isNaN(rMin) || isNaN(rMax)) {
            throw new Error(`Invalid range in segment: "${segment}"`);
          }
          rangeMin = rMin;
          rangeMax = rMax;
        } else {
          rangeMin = parseInt(rangePart, 10);
          if (isNaN(rangeMin)) {
            throw new Error(`Invalid value in segment: "${segment}"`);
          }
          rangeMax = max;
        }
      }
      validateRange(rangeMin, rangeMax, min, max, segment);
      return Array.from({ length: Math.floor((rangeMax - rangeMin) / step) + 1 }, (_, i) => rangeMin + i * step).filter(
        (v) => v >= min && v <= max,
      );
    }

    if (segment.includes("-")) {
      const [startStr, endStr] = segment.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range in segment: "${segment}"`);
      }
      validateRange(start, end, min, max, segment);
      return Array.from({ length: end - start + 1 }, (_, i) => i + start);
    }

    const value = parseInt(segment, 10);
    if (isNaN(value)) {
      throw new Error(`Invalid value "${segment}"`);
    }
    if (value < min || value > max) {
      throw new Error(`Value ${value} out of range [${min}, ${max}]`);
    }
    return [value];
  };

  const validateRange = (start: number, end: number, min: number, max: number, segment: string) => {
    if (start < min || end > max || start > end) {
      throw new Error(`Range "${segment}" is invalid for bounds [${min}, ${max}]`);
    }
  };

  if (expression.includes(",")) {
    const segments = expression.split(",");
    const values = new Set<number>();
    for (const segment of segments) {
      for (const v of parseSegment(segment.trim())) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  return parseSegment(expression);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof CronResult>;
  const exprs = [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr];

  const result = {} as CronResult;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = expandField(exprs[i], min, max);
    } catch (err) {
      throw new Error(`Error in field "${name}" ("${exprs[i]}"): ${(err as Error).message}`);
    }
  }

  return result;
}

export default parseCron;

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

interface FieldMeta {
  min: number;
  /** Inclusive upper bound used for validation; dayOfWeek accepts 7 (= Sunday = 0) */
  max: number;
}

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const FIELD_META: Readonly<Record<CronField, FieldMeta>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 7 is a legal alias for Sunday (0)
} as const;

// ---------------------------------------------------------------------------
// Low-level helpers
// ---------------------------------------------------------------------------

function assertFiniteInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new RangeError(`"${trimmed}" is not a valid non-negative integer (${context})`);
  }
  const n = Number(trimmed);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    // Guard against exotic JS edge cases (e.g. "1e308")
    throw new RangeError(`"${trimmed}" overflows a safe integer (${context})`);
  }
  return n;
}

function assertInRange(n: number, min: number, max: number, context: string): void {
  if (n < min || n > max) {
    throw new RangeError(
      `Value ${n} is outside the allowed range [${min}, ${max}] (${context})`
    );
  }
}

function linearRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} must not exceed end ${end}`);
  }
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function dedupSorted(values: number[]): number[] {
  return Array.from(new Set(values)).sort((a, b) => a - b);
}

// ---------------------------------------------------------------------------
// Per-token parsers (no comma handling — commas are split before this layer)
// ---------------------------------------------------------------------------

/**
 * Parses a single non-comma expression token:
 *   *          – wildcard
 *   N          – single integer
 *   N-M        – range
 *   * /S       – step over full range   (space only for JSDoc; no real space)
 *   N/S        – step starting at N
 *   N-M/S      – step over a sub-range
 */
function parseToken(token: string, meta: FieldMeta, context: string): number[] {
  const { min, max } = meta;

  if (token === "") {
    throw new SyntaxError(`Empty token encountered (${context})`);
  }

  // ── step expression ─────────────────────────────────────────────────────
  const slashIdx = token.indexOf("/");
  if (slashIdx !== -1) {
    const baseExpr = token.slice(0, slashIdx);
    const stepExpr = token.slice(slashIdx + 1);

    if (stepExpr.includes("/")) {
      throw new SyntaxError(`Multiple "/" in a single token "${token}" (${context})`);
    }

    const step = assertFiniteInt(stepExpr, `step in "${token}" (${context})`);
    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer, got ${step} (${context})`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (baseExpr === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (baseExpr.includes("-")) {
      const [s, e, ...extra] = baseExpr.split("-");
      if (extra.length > 0 || s === undefined || e === undefined) {
        throw new SyntaxError(`Invalid range "${baseExpr}" in step expression (${context})`);
      }
      rangeStart = assertFiniteInt(s, `range start (${context})`);
      rangeEnd   = assertFiniteInt(e, `range end (${context})`);
      assertInRange(rangeStart, min, max, `range start (${context})`);
      assertInRange(rangeEnd,   min, max, `range end (${context})`);
      if (rangeStart > rangeEnd) {
        throw new RangeError(
          `Range start ${rangeStart} > end ${rangeEnd} (${context})`
        );
      }
    } else {
      rangeStart = assertFiniteInt(baseExpr, `step base (${context})`);
      assertInRange(rangeStart, min, max, `step base (${context})`);
      rangeEnd = max;
    }

    const out: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) out.push(i);
    return out;
  }

  // ── wildcard ─────────────────────────────────────────────────────────────
  if (token === "*") {
    return linearRange(min, max);
  }

  // ── range ─────────────────────────────────────────────────────────────────
  const dashIdx = token.indexOf("-");
  if (dashIdx !== -1) {
    const [s, e, ...extra] = token.split("-");
    if (extra.length > 0 || s === undefined || e === undefined) {
      throw new SyntaxError(`Invalid range expression "${token}" (${context})`);
    }
    const start = assertFiniteInt(s, `range start (${context})`);
    const end   = assertFiniteInt(e, `range end (${context})`);
    assertInRange(start, min, max, `range start (${context})`);
    assertInRange(end,   min, max, `range end (${context})`);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} (${context})`);
    }
    return linearRange(start, end);
  }

  // ── single value ──────────────────────────────────────────────────────────
  const n = assertFiniteInt(token, context);
  assertInRange(n, min, max, context);
  return [n];
}

/**
 * Parses a full field expression (may contain commas whose sub-expressions
 * are each forwarded to `parseToken`).
 */
function parseField(expr: string, field: CronField): number[] {
  const meta = FIELD_META[field];
  const context = `field "${field}"`;

  if (typeof expr !== "string" || expr.trim() === "") {
    throw new SyntaxError(`Empty or missing expression for ${context}`);
  }

  const trimmed = expr.trim();

  // Comma-separated list
  const parts = trimmed.split(",");
  const collected: number[] = [];

  for (const part of parts) {
    const tok = part.trim();
    if (tok === "") {
      throw new SyntaxError(
        `Empty segment in comma list "${trimmed}" (${context})`
      );
    }
    const values = parseToken(tok, meta, context);
    collected.push(...values);
  }

  // Normalise dayOfWeek: 7 (Sunday) → 0
  const normalised =
    field === "dayOfWeek"
      ? collected.map((v) => (v === 7 ? 0 : v))
      : collected;

  const result = dedupSorted(normalised);

  if (result.length === 0) {
    // Theoretically unreachable, but guard anyway
    throw new RangeError(`Expression "${expr}" produced no values for ${context}`);
  }

  return result;
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Parses a 5-field cron expression into arrays of resolved numeric values.
 *
 * Supported per-field syntax:
 *   *         – every value in the field's valid range
 *   N         – exact value
 *   N-M       – inclusive range
 *   * /S      – every S-th value across the full range  (no space in real use)
 *   N/S       – every S-th value starting from N
 *   N-M/S     – every S-th value within [N, M]
 *   a,b,c     – union of any of the above tokens
 *
 * Valid ranges:
 *   minute     0–59
 *   hour       0–23
 *   dayOfMonth 1–31
 *   month      1–12
 *   dayOfWeek  0–6  (7 is accepted as an alias for Sunday / 0)
 *
 * @throws {TypeError}    if the argument is not a string
 * @throws {SyntaxError}  if the expression is malformed
 * @throws {RangeError}   if a numeric value falls outside its allowed range
 */
export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on any run of whitespace
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields; found ${fields.length} in "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const rawExpr   = fields[i];

    try {
      result[fieldName] = parseField(rawExpr, fieldName);
    } catch (err) {
      // Re-wrap with positional context so callers get one coherent message
      const msg =
        err instanceof Error ? err.message : String(err);
      const Ctor =
        err instanceof TypeError  ? TypeError  :
        err instanceof RangeError ? RangeError :
        SyntaxError;
      throw new Ctor(
        `[field ${i + 1} / "${fieldName}"] ${msg}`
      );
    }
  }

  return result;
}

interface DoublyLinkedNode<T> {
  key: string;
  value: T;
  prev: DoublyLinkedNode<T> | null;
  next: DoublyLinkedNode<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, DoublyLinkedNode<T>>;
  private head: DoublyLinkedNode<T>; // most recently used sentinel
  private tail: DoublyLinkedNode<T>; // least recently used sentinel

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Sentinel nodes eliminate null-checks on boundary operations
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.cache.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    const existing = this.cache.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: DoublyLinkedNode<T> = { key, value, prev: null, next: null };
    this.cache.set(key, node);
    this.insertAtFront(node);

    if (this.cache.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.cache.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.cache.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.cache.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.cache.delete(key);
    return true;
  }

  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: DoublyLinkedNode<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: DoublyLinkedNode<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DoublyLinkedNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      return; // nothing to evict (should not occur under normal usage)
    }

    this.removeNode(lru);
    this.cache.delete(lru.key);
  }
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
] as const;

const isInteger = (value: number): boolean =>
  Number.isFinite(value) && Math.floor(value) === value;

const clampDayOfWeek = (values: number[]): number[] => {
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalized)].sort((a, b) => a - b);
};

const parseNumber = (token: string, config: FieldConfig): number => {
  const num = Number(token);
  if (!isInteger(num)) {
    throw new Error(
      `Invalid value "${token}" in field "${config.name}": must be an integer`
    );
  }
  if (num < config.min || num > config.max) {
    throw new Error(
      `Value ${num} out of range for field "${config.name}": must be between ${config.min} and ${config.max}`
    );
  }
  return num;
};

const expandRange = (min: number, max: number): number[] => {
  if (min > max) {
    throw new Error(`Invalid range: start ${min} is greater than end ${max}`);
  }
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
};

const parseWildcard = (config: FieldConfig): number[] =>
  expandRange(config.min, config.max);

const parseStep = (token: string, config: FieldConfig): number[] => {
  const [baseToken, stepToken, ...extra] = token.split("/");
  if (extra.length > 0) {
    throw new Error(
      `Invalid step expression "${token}" in field "${config.name}"`
    );
  }

  if (stepToken === undefined || stepToken === "") {
    throw new Error(
      `Missing step value in expression "${token}" in field "${config.name}"`
    );
  }

  const step = Number(stepToken);
  if (!isInteger(step) || step < 1) {
    throw new Error(
      `Invalid step value "${stepToken}" in field "${config.name}": must be a positive integer`
    );
  }

  let rangeMin: number;
  let rangeMax: number;

  if (baseToken === "*") {
    rangeMin = config.min;
    rangeMax = config.max;
  } else if (baseToken.includes("-")) {
    const [rangeStartToken, rangeEndToken, ...rangeExtra] =
      baseToken.split("-");
    if (rangeExtra.length > 0) {
      throw new Error(
        `Invalid range expression "${baseToken}" in field "${config.name}"`
      );
    }
    rangeMin = parseNumber(rangeStartToken, config);
    rangeMax = parseNumber(rangeEndToken, config);
    if (rangeMin > rangeMax) {
      throw new Error(
        `Invalid range "${baseToken}" in field "${config.name}": start must not exceed end`
      );
    }
  } else {
    rangeMin = parseNumber(baseToken, config);
    rangeMax = config.max;
  }

  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }
  return values;
};

const parseRange = (token: string, config: FieldConfig): number[] => {
  const parts = token.split("-");
  if (parts.length !== 2) {
    throw new Error(
      `Invalid range expression "${token}" in field "${config.name}"`
    );
  }
  const [startToken, endToken] = parts;
  const start = parseNumber(startToken, config);
  const end = parseNumber(endToken, config);
  if (start > end) {
    throw new Error(
      `Invalid range "${token}" in field "${config.name}": start ${start} must not exceed end ${end}`
    );
  }
  return expandRange(start, end);
};

const parseSingleToken = (token: string, config: FieldConfig): number[] => {
  if (token === "") {
    throw new Error(`Empty token in field "${config.name}"`);
  }

  if (token === "*") {
    return parseWildcard(config);
  }

  if (token.includes("/")) {
    return parseStep(token, config);
  }

  if (token.includes("-")) {
    return parseRange(token, config);
  }

  return [parseNumber(token, config)];
};

const parseField = (expression: string, config: FieldConfig): number[] => {
  if (typeof expression !== "string") {
    throw new Error(`Field "${config.name}" expression must be a string`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error(`Field "${config.name}" expression must not be empty`);
  }

  const segments = trimmed.split(",");
  if (segments.some((s) => s === "")) {
    throw new Error(
      `Field "${config.name}" contains empty segment in list expression`
    );
  }

  const allValues = segments.flatMap((segment) =>
    parseSingleToken(segment.trim(), config)
  );

  const unique = [...new Set(allValues)].sort((a, b) => a - b);
  return unique;
};

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  const minuteConfig = FIELD_CONFIGS[0];
  const hourConfig = FIELD_CONFIGS[1];
  const domConfig = FIELD_CONFIGS[2];
  const monthConfig = FIELD_CONFIGS[3];
  const dowConfig = FIELD_CONFIGS[4];

  const minute = parseField(minuteExpr, minuteConfig);
  const hour = parseField(hourExpr, hourConfig);
  const dayOfMonth = parseField(domExpr, domConfig);
  const month = parseField(monthExpr, monthConfig);
  const rawDayOfWeek = parseField(dowExpr, dowConfig);
  const dayOfWeek = clampDayOfWeek(rawDayOfWeek);

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("LRUCache does not accept undefined as a value");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependToHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") return false;
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head;
    while (current !== null) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private prependToHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.prependToHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const evicted = this.tail;
    this.removeNode(evicted);
    this.map.delete(evicted.key);
  }
}

interface DLLNode<T> {
  key: string;
  value: T;
  prev: DLLNode<T>;
  next: DLLNode<T>;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLLNode<T>>;
  // Sentinel head (MRU side) and tail (LRU side) — avoids null checks on every operation
  private readonly head: DLLNode<T>;
  private readonly tail: DLLNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, received: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes: never hold real data, just anchor the list
    this.head = {} as DLLNode<T>;
    this.tail = {} as DLLNode<T>;
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // A zero-capacity cache is valid but can never hold anything
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      // Update in-place and promote — avoids a spurious eviction for the same key
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: DLLNode<T> = {
      key,
      value,
      prev: null as unknown as DLLNode<T>,
      next: null as unknown as DLLNode<T>,
    };

    this.map.set(key, node);
    this.insertAfterHead(node);

    if (this.map.size > this.capacity) {
      // tail.prev is the LRU real node; never the head sentinel because
      // capacity >= 1 guarantees at least one real node exists here
      const lru = this.tail.prev;
      this.splice(lru);
      this.map.delete(lru.key);
    }
  }

  get size(): number {
    return this.map.size;
  }

  private insertAfterHead(node: DLLNode<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next.prev = node;
    this.head.next = node;
  }

  private splice(node: DLLNode<T>): void {
    node.prev.next = node.next;
    node.next.prev = node.prev;
  }

  private moveToFront(node: DLLNode<T>): void {
    this.splice(node);
    this.insertAfterHead(node);
  }
}

export default LRUCache;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  readonly min: number;
  readonly max: number;
}

const FIELD_BOUNDS: Readonly<Record<keyof CronFields, FieldBounds>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function parseStrictInt(raw: string, context: string): number {
  const s = raw.trim();
  if (s === "" || !/^\d+$/.test(s)) {
    throw new RangeError(`Invalid integer "${s}" in ${context}`);
  }
  const n = parseInt(s, 10);
  if (!Number.isFinite(n)) {
    throw new RangeError(`Overflow parsing "${s}" in ${context}`);
  }
  return n;
}

function assertInBounds(value: number, bounds: FieldBounds, context: string): void {
  if (value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} out of bounds [${bounds.min}, ${bounds.max}] in ${context}`,
    );
  }
}

function buildRange(start: number, end: number, step: number, bounds: FieldBounds, context: string): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step} in ${context}`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in ${context}`);
  }
  assertInBounds(start, bounds, context);
  assertInBounds(end, bounds, context);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, bounds: FieldBounds, context: string): number[] {
  const s = segment.trim();
  if (s === "") {
    throw new SyntaxError(`Empty segment in ${context}`);
  }

  // Step form: "*/n", "a-b/n", or "a/n" (start from a to max)
  const slashIndex = s.indexOf("/");
  if (slashIndex !== -1) {
    const left = s.slice(0, slashIndex);
    const stepRaw = s.slice(slashIndex + 1);

    if (stepRaw === "") {
      throw new SyntaxError(`Missing step value after "/" in ${context}`);
    }

    const step = parseStrictInt(stepRaw, context);

    if (left === "*") {
      return buildRange(bounds.min, bounds.max, step, bounds, context);
    }

    const dashIndex = left.indexOf("-");
    if (dashIndex !== -1) {
      if (dashIndex === 0 || dashIndex === left.length - 1) {
        throw new SyntaxError(`Malformed range "${left}" in ${context}`);
      }
      const start = parseStrictInt(left.slice(0, dashIndex), context);
      const end   = parseStrictInt(left.slice(dashIndex + 1), context);
      return buildRange(start, end, step, bounds, context);
    }

    // "value/step" — start from value, step to max
    const start = parseStrictInt(left, context);
    assertInBounds(start, bounds, context);
    return buildRange(start, bounds.max, step, bounds, context);
  }

  // Wildcard
  if (s === "*") {
    return buildRange(bounds.min, bounds.max, 1, bounds, context);
  }

  // Range: "a-b"
  const dashIndex = s.indexOf("-");
  if (dashIndex !== -1) {
    if (dashIndex === 0 || dashIndex === s.length - 1) {
      throw new SyntaxError(`Malformed range "${s}" in ${context}`);
    }
    // Guard against multiple dashes
    if (s.indexOf("-", dashIndex + 1) !== -1) {
      throw new SyntaxError(`Ambiguous range expression "${s}" in ${context}`);
    }
    const start = parseStrictInt(s.slice(0, dashIndex), context);
    const end   = parseStrictInt(s.slice(dashIndex + 1), context);
    return buildRange(start, end, 1, bounds, context);
  }

  // Single value
  const value = parseStrictInt(s, context);
  assertInBounds(value, bounds, context);
  return [value];
}

function parseField(raw: string, bounds: FieldBounds, fieldName: string): number[] {
  const s = raw.trim();
  if (s === "") {
    throw new SyntaxError(`Empty field for "${fieldName}"`);
  }

  const parts = s.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    if (part.trim() === "") {
      throw new SyntaxError(`Empty segment in comma list for "${fieldName}"`);
    }
    for (const value of parseSegment(part, bounds, `field "${fieldName}"`)) {
      seen.add(value);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(`Field "${fieldName}" produced no valid values`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`,
    );
  }

  return {
    minute:     parseField(fields[0], FIELD_BOUNDS.minute,     FIELD_NAMES[0]),
    hour:       parseField(fields[1], FIELD_BOUNDS.hour,       FIELD_NAMES[1]),
    dayOfMonth: parseField(fields[2], FIELD_BOUNDS.dayOfMonth, FIELD_NAMES[2]),
    month:      parseField(fields[3], FIELD_BOUNDS.month,      FIELD_NAMES[3]),
    dayOfWeek:  parseField(fields[4], FIELD_BOUNDS.dayOfWeek,  FIELD_NAMES[4]),
  };
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value: "${stepPart}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) throw new RangeError(`Invalid step range: "${rangePart}"`);
      assertInRange(s, min, max, segment);
      assertInRange(e, min, max, segment);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new RangeError(`Invalid step base: "${rangePart}"`);
      assertInRange(start, min, max, segment);
      end = max;
    }

    if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new RangeError(`Invalid range expression: "${segment}"`);
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) throw new RangeError(`Invalid range values: "${segment}"`);
    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);
    return range(start, end);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").flatMap((part) => parseSegment(part.trim(), min, max));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new RangeError(`Invalid cron value: "${segment}"`);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new RangeError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    const rawValues = parseSegment(fields[i], min, max);
    result[name] = [...new Set(rawValues)].sort((a, b) => a - b);
  }

  return result;
}

export default parseCron;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  }, // 0 and 7 both represent Sunday
] as const;

const DIGITS_ONLY = /^\d+$/;

function buildRange(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseInteger(raw: string, fieldName: string, context: string): number {
  if (!DIGITS_ONLY.test(raw)) {
    throw new Error(
      `Invalid integer "${raw}" in field '${fieldName}' (${context}). Only non-negative integers are allowed.`
    );
  }
  return parseInt(raw, 10);
}

function assertInBounds(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of bounds [${config.min}, ${config.max}] in field '${config.name}' (${context}).`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  // Wildcard: "*"
  if (segment === "*") {
    return buildRange(min, max, 1);
  }

  // Step on wildcard: "*/n"
  if (segment.startsWith("*/")) {
    const stepRaw = segment.slice(2);
    if (stepRaw === "") {
      throw new Error(`Missing step value after "*/" in field '${name}'.`);
    }
    const step = parseInteger(stepRaw, name, `step "*/n"`);
    if (step === 0) {
      throw new Error(`Step value cannot be zero in field '${name}'.`);
    }
    return buildRange(min, max, step);
  }

  // Range with optional step: "a-b" or "a-b/n"
  if (segment.includes("-")) {
    const slashIdx = segment.indexOf("/");
    let rangeStr: string;
    let step = 1;

    if (slashIdx !== -1) {
      rangeStr = segment.slice(0, slashIdx);
      const stepRaw = segment.slice(slashIdx + 1);
      if (stepRaw === "") {
        throw new Error(`Missing step value after "/" in field '${name}': "${segment}".`);
      }
      step = parseInteger(stepRaw, name, `range step in "${segment}"`);
      if (step === 0) {
        throw new Error(`Step value cannot be zero in field '${name}': "${segment}".`);
      }
    } else {
      rangeStr = segment;
    }

    const dashIdx = rangeStr.indexOf("-");
    if (dashIdx === 0 || dashIdx === rangeStr.length - 1) {
      throw new Error(`Malformed range "${rangeStr}" in field '${name}'.`);
    }

    const startRaw = rangeStr.slice(0, dashIdx);
    const endRaw   = rangeStr.slice(dashIdx + 1);

    const start = parseInteger(startRaw, name, `range start in "${segment}"`);
    const end   = parseInteger(endRaw,   name, `range end in "${segment}"`);

    assertInBounds(start, config, `range start in "${segment}"`);
    assertInBounds(end,   config, `range end in "${segment}"`);

    if (start > end) {
      throw new RangeError(
        `Range start (${start}) must be <= end (${end}) in field '${name}': "${segment}".`
      );
    }

    return buildRange(start, end, step);
  }

  // Plain integer
  if (DIGITS_ONLY.test(segment)) {
    const value = parseInt(segment, 10);
    assertInBounds(value, config, `literal value`);
    return [value];
  }

  throw new Error(
    `Unrecognized segment "${segment}" in field '${name}'. Expected a number, "*", "*/n", "a-b", or "a-b/n".`
  );
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw.trim() === "") {
    throw new Error(`Field '${config.name}' is empty.`);
  }

  const segments = raw.split(",");
  const seen = new Set<number>();

  for (let i = 0; i < segments.length; i++) {
    const segment = segments[i].trim();
    if (segment === "") {
      throw new Error(
        `Empty segment at position ${i + 1} in field '${config.name}': "${raw}". Check for trailing or doubled commas.`
      );
    }

    const values = parseSegment(segment, config);
    for (const v of values) {
      seen.add(v);
    }
  }

  // Return sorted, deduplicated array
  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}.`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression cannot be empty.");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}".`
    );
  }

  return {
    minute:     parseField(fields[0], FIELD_CONFIGS[0]),
    hour:       parseField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    month:      parseField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(fields[4], FIELD_CONFIGS[4]),
  };
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T>; // Most recently used sentinel
  private tail: Node<T>; // Least recently used sentinel

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes to avoid null checks on boundary operations
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove an entry");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      return;
    }

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, { value: T; prev: string | null; next: string | null }>;
  private head: string | null = null;
  private tail: string | null = null;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;
    this.moveToHead(key);
    return node.value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.get(key)!.value = value;
      this.moveToHead(key);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictTail();
    }

    this.map.set(key, { value, prev: null, next: this.head });

    if (this.head !== null) {
      this.map.get(this.head)!.prev = key;
    }

    this.head = key;

    if (this.tail === null) {
      this.tail = key;
    }
  }

  private moveToHead(key: string): void {
    if (this.head === key) return;

    const node = this.map.get(key)!;
    const { prev, next } = node;

    if (prev !== null) {
      this.map.get(prev)!.next = next;
    }

    if (next !== null) {
      this.map.get(next)!.prev = prev;
    }

    if (this.tail === key) {
      this.tail = prev;
    }

    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.map.get(this.head)!.prev = key;
    }

    this.head = key;
  }

  private evictTail(): void {
    if (this.tail === null) return;

    const tailKey = this.tail;
    const tailNode = this.map.get(tailKey)!;

    if (tailNode.prev !== null) {
      this.map.get(tailNode.prev)!.next = null;
    }

    this.tail = tailNode.prev;

    if (this.tail === null) {
      this.head = null;
    }

    this.map.delete(tailKey);
  }
}

export default LRUCache;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_LIMITS: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const RE_INTEGER = /^\d+$/;

function buildRange(start: number, end: number, step = 1): number[] {
  if (step < 1) throw new RangeError(`Step must be >= 1, got ${step}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseInteger(raw: string, field: FieldName): number {
  if (!RE_INTEGER.test(raw)) {
    throw new TypeError(
      `Expected an integer in field "${field}", got "${raw}"`
    );
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, field: FieldName): void {
  const { min, max } = FIELD_LIMITS[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseFieldExpression(expr: string, field: FieldName): number[] {
  if (expr === "") {
    throw new SyntaxError(`Empty expression for field "${field}"`);
  }

  const { min, max } = FIELD_LIMITS[field];

  // Wildcard: *
  if (expr === "*") {
    return buildRange(min, max);
  }

  // Step: */n  or  a-b/n
  if (expr.includes("/")) {
    const slashIdx = expr.indexOf("/");
    const base = expr.slice(0, slashIdx);
    const stepRaw = expr.slice(slashIdx + 1);

    if (!RE_INTEGER.test(stepRaw)) {
      throw new TypeError(
        `Invalid step value "${stepRaw}" in field "${field}"`
      );
    }

    const step = parseInt(stepRaw, 10);
    if (step < 1) {
      throw new RangeError(
        `Step must be >= 1 in field "${field}", got ${step}`
      );
    }

    let rangeMin = min;
    let rangeMax = max;

    if (base !== "*") {
      if (!base.includes("-")) {
        throw new SyntaxError(
          `Step base must be "*" or a range in field "${field}", got "${base}"`
        );
      }
      const [startRaw, endRaw] = base.split("-");
      rangeMin = parseInteger(startRaw, field);
      rangeMax = parseInteger(endRaw, field);
      assertInRange(rangeMin, field);
      assertInRange(rangeMax, field);
      if (rangeMin > rangeMax) {
        throw new RangeError(
          `Range start ${rangeMin} > end ${rangeMax} in field "${field}"`
        );
      }
    }

    return buildRange(rangeMin, rangeMax, step);
  }

  // Range: a-b  (no comma, no slash)
  if (expr.includes("-") && !expr.includes(",")) {
    const dashParts = expr.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid range "${expr}" in field "${field}": expected exactly one "-"`
      );
    }
    const start = parseInteger(dashParts[0], field);
    const end   = parseInteger(dashParts[1], field);
    assertInRange(start, field);
    assertInRange(end, field);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} > end ${end} in field "${field}"`
      );
    }
    return buildRange(start, end);
  }

  // Comma-separated list: may include numbers, ranges, and steps
  if (expr.includes(",")) {
    const seen = new Set<number>();
    const parts = expr.split(",");

    for (const part of parts) {
      if (part === "") {
        throw new SyntaxError(
          `Empty segment in comma list for field "${field}": "${expr}"`
        );
      }
      // Each segment may itself be a number, range, or step — recurse
      const segValues = parseFieldExpression(part, field);
      for (const v of segValues) {
        seen.add(v);
      }
    }

    return [...seen].sort((a, b) => a - b);
  }

  // Single integer
  const num = parseInteger(expr, field);
  assertInRange(num, field);
  return [num];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const expr  = rawFields[i];
    result[field] = parseFieldExpression(expr, field);
  }

  return result;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `Capacity must be a non-negative integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) return undefined;
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache: writes are always silently dropped
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prepend(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  private moveToFront(node: Node<T>): void {
    if (node === this.head) return;
    this.detach(node);
    this.prepend(node);
  }

  private detach(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }
    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }
    node.prev = null;
    node.next = null;
  }

  private prepend(node: Node<T>): void {
    node.next = this.head;
    node.prev = null;
    if (this.head !== null) {
      this.head.prev = node;
    }
    this.head = node;
    if (this.tail === null) {
      this.tail = node;
    }
  }

  private evictLRU(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.detach(lru);
    this.map.delete(lru.key);
  }
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | unknown;
};

type FlattenedObject = Record<string, Primitive | unknown[]>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    preserveArrays?: boolean;
  } = {}
): FlattenedObject {
  const {
    delimiter = ".",
    maxDepth = Infinity,
    preserveArrays = true,
  } = options;

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject: expected a plain object, got ${input === null ? "null" : typeof input}`
    );
  }

  if (
    typeof maxDepth !== "number" ||
    maxDepth < 1 ||
    !Number.isFinite(maxDepth)
  ) {
    throw new RangeError(
      "flattenObject: maxDepth must be a finite number >= 1"
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (isPlainObject(current)) {
      if (seen.has(current as object)) {
        throw new TypeError(
          `flattenObject: circular reference detected at key "${prefix}"`
        );
      }

      const keys = Object.keys(current as NestedObject);

      // Emit empty objects as-is under their key
      if (keys.length === 0) {
        if (prefix !== "") {
          (result as Record<string, unknown>)[prefix] = current;
        }
        return;
      }

      // Stop recursing if we've hit the max depth
      if (depth >= maxDepth) {
        if (prefix !== "") {
          (result as Record<string, unknown>)[prefix] = current;
        }
        return;
      }

      seen.add(current as object);

      for (const key of keys) {
        if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

        // Guard against prototype pollution via malicious keys
        if (key === "__proto__" || key === "constructor" || key === "prototype") {
          continue;
        }

        const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
        recurse((current as NestedObject)[key], newKey, depth + 1);
      }

      seen.delete(current as object);
    } else if (Array.isArray(current)) {
      if (preserveArrays || depth >= maxDepth) {
        // Treat arrays as leaf values
        (result as Record<string, unknown>)[prefix] = current;
      } else {
        if (current.length === 0) {
          (result as Record<string, unknown>)[prefix] = current;
          return;
        }
        seen.add(current);
        for (let i = 0; i < current.length; i++) {
          const newKey = `${prefix}${delimiter}${i}`;
          recurse(current[i], newKey, depth + 1);
        }
        seen.delete(current);
      }
    } else {
      // Primitive or non-plain-object — emit as leaf
      (result as Record<string, unknown>)[prefix] = current;
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
  readonly name: string;
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59, name: "minute"     },
  hour:       { min: 0,  max: 23, name: "hour"        },
  dayOfMonth: { min: 1,  max: 31, name: "dayOfMonth"  },
  month:      { min: 1,  max: 12, name: "month"       },
  dayOfWeek:  { min: 0,  max: 7,  name: "dayOfWeek"   },
} as const satisfies Record<keyof CronFields, FieldRange>;

const FIELD_ORDER: ReadonlyArray<keyof CronFields> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

const INTEGER_RE = /^\d+$/;

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(
      `${context}: value ${value} is outside valid range [${range.min}–${range.max}] for field "${range.name}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!INTEGER_RE.test(trimmed)) {
    throw new TypeError(`${context}: expected an integer, got "${raw}"`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n)) {
    throw new TypeError(`${context}: parsed value is not finite for input "${raw}"`);
  }
  return n;
}

function expandRange(start: number, end: number, step: number, range: FieldRange, context: string): number[] {
  if (step <= 0) {
    throw new RangeError(`${context}: step must be a positive integer, got ${step}`);
  }
  if (start > end) {
    throw new RangeError(`${context}: range start ${start} must not exceed end ${end}`);
  }
  assertInRange(start, range, context);
  assertInRange(end, range, context);

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  // Guard against pathological step producing empty slice (shouldn't happen given start <= end)
  if (values.length === 0) {
    throw new RangeError(`${context}: step expression produced no values`);
  }
  return values;
}

function parseSegment(segment: string, range: FieldRange): number[] {
  const context = `field "${range.name}", segment "${segment}"`;

  if (segment.trim() === "") {
    throw new TypeError(`${context}: segment must not be empty`);
  }

  // Step value: <base>/<step>  where base is *, <number>, or <a>-<b>
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`${context}: step expression must have exactly one "/" separator`);
    }
    const [baseExpr, stepExpr] = slashParts;
    const step = parseInteger(stepExpr, `${context} (step)`);
    if (step <= 0) {
      throw new RangeError(`${context}: step must be a positive integer, got ${step}`);
    }

    if (baseExpr === "*") {
      return expandRange(range.min, range.max, step, range, context);
    }

    if (baseExpr.includes("-")) {
      const dashParts = baseExpr.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`${context}: range in step expression must have exactly one "-" separator`);
      }
      const start = parseInteger(dashParts[0], `${context} (range start)`);
      const end   = parseInteger(dashParts[1], `${context} (range end)`);
      return expandRange(start, end, step, range, context);
    }

    // <number>/<step> — start at number, go to max
    const start = parseInteger(baseExpr, `${context} (step base)`);
    return expandRange(start, range.max, step, range, context);
  }

  // Wildcard: expand full field range
  if (segment === "*") {
    const values: number[] = [];
    for (let v = range.min; v <= range.max; v++) {
      values.push(v);
    }
    return values;
  }

  // Range: <a>-<b>
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`${context}: range must have exactly one "-" separator`);
    }
    const start = parseInteger(dashParts[0], `${context} (range start)`);
    const end   = parseInteger(dashParts[1], `${context} (range end)`);
    return expandRange(start, end, 1, range, context);
  }

  // Single integer
  const n = parseInteger(segment, context);
  assertInRange(n, range, context);
  return [n];
}

function parseField(raw: string, range: FieldRange): number[] {
  if (raw === null || raw === undefined) {
    throw new TypeError(`Field "${range.name}" must not be null or undefined`);
  }
  if (raw.trim() === "") {
    throw new TypeError(`Field "${range.name}" must not be empty or whitespace`);
  }

  const segments = raw.split(",");
  const seen = new Set<number>();

  for (let i = 0; i < segments.length; i++) {
    const seg = segments[i].trim();
    if (seg === "") {
      throw new SyntaxError(
        `Field "${range.name}": empty segment at position ${i} in comma-separated list "${raw}"`
      );
    }
    for (const v of parseSegment(seg, range)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(`Field "${range.name}": expression "${raw}" produced no valid values`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must be a non-null, non-undefined string");
  }
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new TypeError("Cron expression must not be empty or whitespace");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${parts.length} field(s) in: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const rawPart = parts[i];
    // Each field is independently parsed; one failing field surfaces a clear error
    result[fieldName] = parseField(rawPart, FIELD_RANGES[fieldName]);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 64
): FlattenedObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};

  function recurse(
    current: Record<string, unknown>,
    prefix: string,
    depth: number
  ): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    const keys = Object.keys(current);

    for (const key of keys) {
      if (key === "") {
        // Empty string keys would produce confusing dot-notation like "a..b"
        // We still include them but flag with a marker to avoid silent data loss
        const fullKey = prefix !== "" ? `${prefix}.${key}` : key;
        const value = current[key];
        if (isPlainObject(value) && Object.keys(value).length > 0) {
          recurse(value, fullKey, depth + 1);
        } else {
          result[fullKey] = value as Primitive;
        }
        continue;
      }

      const fullKey = prefix !== "" ? `${prefix}.${key}` : key;
      const value = current[key];

      if (isPlainObject(value)) {
        if (Object.keys(value).length === 0) {
          // Preserve empty objects as explicit null-ish markers rather than silently dropping them
          result[fullKey] = null;
        } else {
          recurse(value, fullKey, depth + 1);
        }
      } else if (Array.isArray(value)) {
        // Arrays are not recursed into — stored as-is to avoid ambiguous numeric keys
        result[fullKey] = value as unknown as Primitive;
      } else {
        result[fullKey] = value as Primitive;
      }
    }
  }

  // Guard against circular references by tracking visited objects
  const seen = new WeakSet<object>();

  function recurseWithCycleDetection(
    current: Record<string, unknown>,
    prefix: string,
    depth: number
  ): void {
    if (seen.has(current)) {
      throw new TypeError(
        `flattenObject detected a circular reference at key path: "${prefix}"`
      );
    }

    seen.add(current);

    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    const keys = Object.keys(current);

    for (const key of keys) {
      const fullKey = prefix !== "" ? `${prefix}.${key}` : key;
      const value = current[key];

      if (isPlainObject(value)) {
        if (Object.keys(value).length === 0) {
          result[fullKey] = null;
        } else {
          recurseWithCycleDetection(value, fullKey, depth + 1);
        }
      } else if (Array.isArray(value)) {
        result[fullKey] = value as unknown as Primitive;
      } else {
        result[fullKey] = value as Primitive;
      }
    }

    // Do NOT delete from seen — a node reachable via two paths is not a cycle,
    // but a node that contains itself is. WeakSet membership here is path-independent,
    // so we accept the conservative false-positive for deeply diamond-shaped graphs
    // in exchange for guaranteed cycle safety.
  }

  recurseWithCycleDetection(input, "", 0);

  // Suppress the unused `recurse` declaration warning — it exists as a simpler
  // reference implementation kept intentionally for auditability.
  void recurse;

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Readonly<Record<CronField, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (!Number.isInteger(value) || value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${range.min}–${range.max}] in segment "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  if (start > end) {
    throw new RangeError(`Range start (${start}) must not exceed end (${end})`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, range: FieldRange): number[] {
  if (!segment || /\s/.test(segment)) {
    throw new SyntaxError(`Invalid cron segment: "${segment}"`);
  }

  // Step expression: */n  |  a-b/n  |  a/n
  if (segment.includes("/")) {
    const slashIndex = segment.indexOf("/");
    const base = segment.slice(0, slashIndex);
    const stepStr = segment.slice(slashIndex + 1);

    if (!stepStr || !/^\d+$/.test(stepStr)) {
      throw new SyntaxError(`Invalid step value in segment "${segment}"`);
    }
    const step = parseInt(stepStr, 10);
    if (step <= 0) {
      throw new RangeError(`Step must be positive in segment "${segment}"`);
    }

    if (base === "*") {
      return expandRange(range.min, range.max, step);
    }

    if (base.includes("-")) {
      const [startStr, endStr, ...extra] = base.split("-");
      if (extra.length > 0 || !startStr || !endStr) {
        throw new SyntaxError(`Invalid range in segment "${segment}"`);
      }
      if (!/^\d+$/.test(startStr) || !/^\d+$/.test(endStr)) {
        throw new SyntaxError(`Non-numeric range bounds in segment "${segment}"`);
      }
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      assertInRange(start, range, segment);
      assertInRange(end, range, segment);
      return expandRange(start, end, step);
    }

    if (!/^\d+$/.test(base)) {
      throw new SyntaxError(`Invalid base value in segment "${segment}"`);
    }
    const start = parseInt(base, 10);
    assertInRange(start, range, segment);
    return expandRange(start, range.max, step);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(range.min, range.max, 1);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr, ...extra] = segment.split("-");
    if (extra.length > 0 || !startStr || !endStr) {
      throw new SyntaxError(`Invalid range expression "${segment}"`);
    }
    if (!/^\d+$/.test(startStr) || !/^\d+$/.test(endStr)) {
      throw new SyntaxError(`Non-numeric range bounds in segment "${segment}"`);
    }
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    assertInRange(start, range, segment);
    assertInRange(end, range, segment);
    return expandRange(start, end, 1);
  }

  // Single number
  if (!/^\d+$/.test(segment)) {
    throw new SyntaxError(`Invalid cron segment "${segment}": expected a number, range, step, or wildcard`);
  }
  const value = parseInt(segment, 10);
  assertInRange(value, range, segment);
  return [value];
}

function parseField(fieldExpression: string, range: FieldRange): number[] {
  if (!fieldExpression || fieldExpression.trim() === "") {
    throw new SyntaxError("Cron field expression must not be empty");
  }

  const segments = fieldExpression.split(",");
  if (segments.some((s) => s === "")) {
    throw new SyntaxError(
      `Trailing or double comma in field expression "${fieldExpression}"`
    );
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field expression "${fieldExpression}"`);
    }
    for (const value of parseSegment(trimmed, range)) {
      valueSet.add(value);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: unknown): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${expression === null ? "null" : typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const range = FIELD_RANGES[field];
    try {
      result[field] = parseField(fields[i], range);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof RangeError ? RangeError : SyntaxError)(
        `Invalid cron field "${field}" (position ${i + 1}): ${message}`
      );
    }
  }

  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number, step = 1): number[] {
  if (step <= 0) throw new Error(`Step must be a positive integer`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function clamp(values: number[], min: number, max: number, field: string): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new Error(`Value ${v} out of range [${min}, ${max}] for field "${field}"`);
    }
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Wildcard: *
  if (segment === "*") {
    return generateRange(min, max);
  }

  // Step on wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    return clamp(generateRange(min, max, step), min, max, field);
  }

  // Range with optional step: n-m or n-m/s
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end = parseInt(rangeMatch[2], 10);
    const step = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;
    if (start > end) {
      throw new Error(`Range start ${start} is greater than end ${end} for field "${field}"`);
    }
    return clamp(generateRange(start, end, step), min, max, field);
  }

  // Single number: n
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    return clamp([value], min, max, field);
  }

  throw new Error(`Invalid cron segment "${segment}" for field "${field}"`);
}

function parseField(expression: string, min: number, max: number, field: string): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const parsed = parseSegment(part.trim(), min, max, field);
    for (const v of parsed) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const exprs = [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr];

  const result = {} as CronResult;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(exprs[i], min, max, key);
  }

  return result;
}

type NestedObject = { [key: string]: unknown };
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at path "${prefix || "<root>"}"`
    );
  }

  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      flattenObjectInternal(value, flatKey, result, ancestors);
    } else {
      // Leaf: primitives, arrays, Dates, RegExps, null, undefined,
      // and empty plain objects (would vanish if recursed into)
      result[flatKey] = value;
    }
  }

  // Remove from ancestor tracking so the same object reference can
  // legitimately appear in sibling branches (shared refs ≠ cycles)
  ancestors.delete(obj);
}

export default function flattenObject(obj: NestedObject): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flattenObjectInternal(obj, "", result, new WeakSet());
  return result;
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof ParsedCron;

const FIELD_ORDER: readonly FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function parseStrictInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid integer "${trimmed}" in ${context}: must be a non-negative whole number`
    );
  }
  return parseInt(trimmed, 10);
}

function expandRange(start: number, end: number): number[] {
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertWithinBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} in "${context}" is out of bounds [${min}, ${max}]`
    );
  }
}

function parseAtom(segment: string, min: number, max: number, field: FieldName): number[] {
  // Wildcard: * — expands to full field range
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Step: */n or start/n or start-end/n
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const baseStr = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);

    if (!stepStr || stepStr.includes("/")) {
      throw new Error(`Malformed step expression "${segment}" in field "${field}"`);
    }

    const step = parseStrictInteger(stepStr, `step in field "${field}"`);
    if (step === 0) {
      throw new Error(`Step value of 0 is invalid in field "${field}" — would cause infinite loop`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (baseStr !== "*") {
      if (baseStr.includes("-")) {
        const dashIdx = baseStr.indexOf("-");
        const startVal = parseStrictInteger(baseStr.slice(0, dashIdx), `range start in field "${field}"`);
        const endVal   = parseStrictInteger(baseStr.slice(dashIdx + 1), `range end in field "${field}"`);
        assertWithinBounds(startVal, min, max, `${field} range`);
        assertWithinBounds(endVal,   min, max, `${field} range`);
        if (startVal > endVal) {
          throw new Error(`Range start ${startVal} > end ${endVal} in field "${field}"`);
        }
        rangeMin = startVal;
        rangeMax = endVal;
      } else {
        const startVal = parseStrictInteger(baseStr, `step base in field "${field}"`);
        assertWithinBounds(startVal, min, max, `${field} step base`);
        rangeMin = startVal;
        // step from a fixed start walks to rangeMax (field max)
      }
    }

    const result: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) result.push(v);
    // result may be empty only if rangeMin > rangeMax, already guarded above
    return result;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const startStr = segment.slice(0, dashIdx);
    const endStr   = segment.slice(dashIdx + 1);

    if (!startStr || !endStr || endStr.includes("-")) {
      throw new Error(`Malformed range "${segment}" in field "${field}"`);
    }

    const start = parseStrictInteger(startStr, `range start in field "${field}"`);
    const end   = parseStrictInteger(endStr,   `range end in field "${field}"`);
    assertWithinBounds(start, min, max, `${field} range`);
    assertWithinBounds(end,   min, max, `${field} range`);

    return expandRange(start, end);
  }

  // Single numeric value
  const value = parseStrictInteger(segment, `value in field "${field}"`);
  assertWithinBounds(value, min, max, field);
  return [value];
}

function parseField(raw: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (!raw || raw.trim() === "") {
    throw new Error(`Field "${field}" is empty`);
  }

  const parts = raw.split(",");
  if (parts.some((p) => p.trim() === "")) {
    throw new Error(
      `Field "${field}" has an empty segment (check for leading/trailing/double commas)`
    );
  }

  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    // Disallow nested commas — parseAtom receives a single atom
    for (const v of parseAtom(trimmed, min, max, field)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  // Collapse internal whitespace runs to single spaces, then split
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const raw   = fields[i];
    // parseField throws descriptively on any invalid input
    result[field] = parseField(raw, field);
  }

  // Sanity-check: no field should ever be empty after parsing
  for (const field of FIELD_ORDER) {
    if (result[field].length === 0) {
      throw new Error(
        `Field "${field}" resolved to an empty value set — expression may be valid syntax ` +
        `but produces no matching times`
      );
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive | Date | RegExp | Function };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof WeakMap) return false;
  if (value instanceof WeakSet) return false;
  if (value instanceof ArrayBuffer) return false;
  if (ArrayBuffer.isView(value)) return false;
  return true;
}

function flattenObjectInternal(
  input: unknown,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>,
): void {
  if (!isPlainObject(input) && !Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return;
  }

  const obj = input as object;

  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`,
    );
  }

  seen.add(obj);

  const entries = Array.isArray(obj)
    ? (obj as unknown[]).map((v, i) => [String(i), v] as [string, unknown])
    : Object.entries(obj as NestedObject);

  if (entries.length === 0) {
    if (prefix !== "") {
      result[prefix] = Array.isArray(obj) ? (obj as unknown as Primitive) : ({} as unknown as Primitive);
    }
    seen.delete(obj);
    return;
  }

  for (const [key, value] of entries) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const newKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value) || Array.isArray(value)) {
      flattenObjectInternal(value, newKey, result, seen);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  seen.delete(obj);
}

export function flattenObject(input: unknown): FlatObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input) && !Array.isArray(input)) {
    return {};
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();

  flattenObjectInternal(input, "", result, seen);

  return result;
}

export default flattenObject;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove an entry");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head.next;
    while (current !== null && current !== this.tail) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      return;
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type Scalar = string | number | boolean | null | undefined | bigint | symbol;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function isTraversable(value: unknown): boolean {
  if (Array.isArray(value)) return value.length > 0;
  if (isPlainObject(value)) return Object.keys(value as object).length > 0;
  return false;
}

function flattenObject(
  input: Record<string, unknown> | unknown[],
  prefix = "",
  seen = new WeakSet<object>()
): Record<string, unknown> {
  if (typeof input !== "object" || input === null) {
    throw new TypeError(`flattenObject expects a non-null object, got ${input === null ? "null" : typeof input}`);
  }

  if (seen.has(input)) {
    throw new Error(`Circular reference detected${prefix ? ` at path "${prefix}"` : ""}`);
  }
  seen.add(input);

  const result: Record<string, unknown> = {};
  const entries = Array.isArray(input)
    ? input.map((v, i) => [String(i), v] as [string, unknown])
    : Object.entries(input);

  for (const [key, value] of entries) {
    // Guard against prototype-polluting keys
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isTraversable(value)) {
      const nested = flattenObject(
        value as Record<string, unknown> | unknown[],
        fullKey,
        seen
      );
      Object.assign(result, nested);
    } else {
      // Leaf: scalar, empty object {}, empty array [], Date, RegExp, null, undefined, etc.
      result[fullKey] = value;
    }
  }

  seen.delete(input);
  return result;
}

export default flattenObject;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (least recently used) and tail (most recently used)
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToTail(node);
    return node.value;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToTail(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertAtTail(node);
    this.map.set(key, node);
  }

  private insertAtTail(node: Node<T>): void {
    const prev = this.tail.prev!;
    prev.next = node;
    node.prev = prev;
    node.next = this.tail;
    this.tail.prev = node;
  }

  private removeNode(node: Node<T>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private moveToTail(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtTail(node);
  }

  private evictLRU(): void {
    const lru = this.head.next;
    // Guard: if lru is the tail sentinel, the cache is empty — nothing to evict
    if (lru === null || lru === this.tail) {
      return;
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("LRUCache does not accept undefined as a value");
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prepend(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head;
    while (current !== null) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private prepend(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;
    if (this.head !== null) {
      this.head.prev = node;
    }
    this.head = node;
    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }
    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }
    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.prepend(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  }, // 7 is a Sunday alias; normalised → 0
] as const;

// Matches only non-negative integers (no leading zeros beyond "0" itself)
const INTEGER_PATTERN = /^(0|[1-9]\d*)$/;

function assertInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!INTEGER_PATTERN.test(trimmed)) {
    throw new RangeError(
      `Expected a non-negative integer in ${context}, got: "${raw}"`
    );
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isSafeInteger(n)) {
    throw new RangeError(`Integer overflow in ${context}: "${raw}"`);
  }
  return n;
}

/**
 * Expand a single segment (no commas) into a sorted list of integers.
 * Supports: "*", "N", "N-M", "* /S", "N-M/S", "N/S"
 */
function expandSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;
  // The effective max for dayOfWeek allows 7 as a Sunday alias.
  const effectiveMax = name === "dayOfWeek" ? 7 : max;

  // Split off an optional /step suffix.
  const slashIdx = segment.indexOf("/");
  let body: string;
  let step: number;

  if (slashIdx !== -1) {
    body = segment.slice(0, slashIdx);
    const rawStep = segment.slice(slashIdx + 1);
    step = assertInteger(rawStep, `${name} step`);
    if (step <= 0) {
      throw new RangeError(`Step must be ≥ 1 for ${name}, got: ${step}`);
    }
    if (step > effectiveMax - min) {
      throw new RangeError(
        `Step ${step} exceeds the valid span [${min}–${effectiveMax}] for ${name}`
      );
    }
  } else {
    body = segment;
    step = 1;
  }

  // Resolve the body to [rangeStart, rangeEnd].
  let rangeStart: number;
  let rangeEnd: number;

  if (body === "*") {
    rangeStart = min;
    rangeEnd   = effectiveMax;
  } else if (body.includes("-")) {
    const dashIdx = body.indexOf("-");
    if (dashIdx === 0 || dashIdx === body.length - 1) {
      throw new RangeError(`Invalid range format in ${name}: "${body}"`);
    }
    rangeStart = assertInteger(body.slice(0, dashIdx), `${name} range start`);
    rangeEnd   = assertInteger(body.slice(dashIdx + 1), `${name} range end`);
    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start (${rangeStart}) must not exceed end (${rangeEnd}) for ${name}`
      );
    }
  } else {
    // Single number — with a /step it acts as "start to max"; without, it's exact.
    rangeStart = assertInteger(body, name);
    rangeEnd   = slashIdx !== -1 ? effectiveMax : rangeStart;
  }

  // Bounds check the resolved range.
  if (rangeStart < min || rangeStart > effectiveMax) {
    throw new RangeError(
      `Value ${rangeStart} out of [${min}–${effectiveMax}] for ${name}`
    );
  }
  if (rangeEnd < min || rangeEnd > effectiveMax) {
    throw new RangeError(
      `Value ${rangeEnd} out of [${min}–${effectiveMax}] for ${name}`
    );
  }

  const values: number[] = [];
  for (let v = rangeStart; v <= rangeEnd; v += step) {
    values.push(v);
  }
  return values;
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { name, min } = config;
  const trimmed = raw.trim();

  if (trimmed.length === 0) {
    throw new RangeError(`Field "${name}" is empty`);
  }

  const segments = trimmed.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    const seg = segment.trim();
    if (seg.length === 0) {
      throw new RangeError(
        `Empty segment in comma-separated list for "${name}": "${raw}"`
      );
    }

    const expanded = expandSegment(seg, config);

    for (const v of expanded) {
      // Normalise dayOfWeek 7 → 0 (both represent Sunday).
      const normalised = name === "dayOfWeek" && v === 7 ? 0 : v;
      seen.add(normalised);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(
      `Field "${name}" produced no valid values from: "${raw}"`
    );
  }

  // Return a deduplicated, ascending, bounds-safe array.
  const result = Array.from(seen).sort((a, b) => a - b);

  // Final sanity check — every normalised value must be within [min, max].
  for (const v of result) {
    const effectiveMax = name === "dayOfWeek" ? 6 : config.max;
    if (v < min || v > effectiveMax) {
      throw new RangeError(
        `Normalised value ${v} out of [${min}–${effectiveMax}] for "${name}"`
      );
    }
  }

  return result;
}

/**
 * Parse a standard 5-field cron expression into arrays of valid trigger values.
 *
 * Fields: minute hour dayOfMonth month dayOfWeek
 *
 * Each field supports: *, N, N-M, *\/S, N-M/S, N/S, and comma-separated
 * combinations of the above (except bare *).
 *
 * @throws {TypeError}  if `expression` is not a string
 * @throws {RangeError} if the expression is malformed or values are out of range
 */
export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received: ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new RangeError("Cron expression must not be empty");
  }

  // Split on any run of whitespace.
  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new RangeError(
      `Cron expression must have exactly 5 fields (got ${parts.length}): "${expression}"`
    );
  }

  return {
    minute:     parseField(parts[0], FIELD_CONFIGS[0]),
    hour:       parseField(parts[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(parts[2], FIELD_CONFIGS[2]),
    month:      parseField(parts[3], FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(parts[4], FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type NestedObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    safe?: boolean;
  } = {}
): Record<string, Primitive> {
  const { delimiter = ".", maxDepth = Infinity, safe = true } = options;

  if (delimiter === "") {
    throw new Error("Delimiter must be a non-empty string");
  }

  if (!isPlainObject(input)) {
    if (input === null || input === undefined) return {};
    throw new TypeError(`Input must be a plain object, received: ${typeof input}`);
  }

  const result: Record<string, Primitive> = {};
  const seen = safe ? new WeakSet<object>() : null;

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      result[prefix] = String(current);
      return;
    }

    if (isPlainObject(current)) {
      if (seen) {
        if (seen.has(current)) {
          throw new Error(`Circular reference detected at key: "${prefix}"`);
        }
        seen.add(current);
      }

      const keys = Object.keys(current as NestedObject);

      if (keys.length === 0) {
        if (prefix !== "") {
          result[prefix] = {};
        }
        return;
      }

      for (const key of keys) {
        if (key.includes(delimiter)) {
          throw new Error(
            `Key "${key}" contains the delimiter "${delimiter}" which would produce ambiguous output`
          );
        }

        const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
        const value = (current as NestedObject)[key];
        recurse(value, newKey, depth + 1);
      }

      if (seen) {
        seen.delete(current);
      }
    } else if (Array.isArray(current)) {
      // Treat arrays as leaf values to avoid ambiguity with numeric keys
      result[prefix] = JSON.stringify(current);
    } else {
      result[prefix] = current as Primitive;
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Readonly<Record<FieldName, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

/**
 * Parses a non-negative integer from a string, rejecting floats, negatives,
 * leading signs, and non-numeric content.
 */
function parseNonNegativeInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid integer "${trimmed}" in ${context}: must contain only digits`
    );
  }
  const value = Number(trimmed);
  if (!Number.isSafeInteger(value)) {
    throw new Error(
      `Integer "${trimmed}" in ${context} exceeds safe integer bounds`
    );
  }
  return value;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} in ${context} is out of valid range [${min}, ${max}]`
    );
  }
}

function deduplicateAndSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

/**
 * Expands a single cron field token (no commas) into an array of integers.
 * Handles: wildcard (*), step (start/step or start-end/step),
 * range (start-end), and literal integers.
 */
function expandToken(
  token: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const context = `field "${fieldName}"`;

  // Step expression: base/step
  if (token.includes("/")) {
    const slashIndex = token.indexOf("/");
    const afterSlash = token.slice(slashIndex + 1);
    const beforeSlash = token.slice(0, slashIndex);

    if (afterSlash.includes("/")) {
      throw new Error(`Multiple "/" separators in ${context}: "${token}"`);
    }

    const step = parseNonNegativeInteger(afterSlash, `${context} step`);
    if (step === 0) {
      throw new Error(`Step value must be ≥ 1 in ${context}: "${token}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (beforeSlash === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (beforeSlash.includes("-")) {
      [rangeMin, rangeMax] = parseRange(beforeSlash, min, max, fieldName);
    } else {
      rangeMin = parseNonNegativeInteger(beforeSlash, context);
      assertInRange(rangeMin, min, max, context);
      rangeMax = max;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (token === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range expression: start-end
  if (token.includes("-")) {
    const [start, end] = parseRange(token, min, max, fieldName);
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Literal integer
  const value = parseNonNegativeInteger(token, `field "${fieldName}"`);
  assertInRange(value, min, max, `field "${fieldName}"`);
  return [value];
}

/**
 * Parses and validates a "start-end" range token, returning [start, end].
 */
function parseRange(
  token: string,
  min: number,
  max: number,
  fieldName: string
): [number, number] {
  const context = `field "${fieldName}"`;
  const dashCount = (token.match(/-/g) ?? []).length;
  if (dashCount !== 1) {
    throw new Error(
      `Range "${token}" in ${context} must contain exactly one "-" separator`
    );
  }

  const dashIndex = token.indexOf("-");
  const startStr = token.slice(0, dashIndex);
  const endStr = token.slice(dashIndex + 1);

  if (!startStr || !endStr) {
    throw new Error(
      `Range "${token}" in ${context} is missing start or end value`
    );
  }

  const start = parseNonNegativeInteger(startStr, `${context} range start`);
  const end = parseNonNegativeInteger(endStr, `${context} range end`);

  assertInRange(start, min, max, `${context} range start`);
  assertInRange(end, min, max, `${context} range end`);

  if (start > end) {
    throw new Error(
      `Range start (${start}) exceeds end (${end}) in ${context}: "${token}"`
    );
  }

  return [start, end];
}

/**
 * Expands a full cron field (which may contain commas) into a sorted,
 * deduplicated array of valid integer values.
 */
function expandField(
  field: string,
  { min, max }: FieldRange,
  fieldName: string
): number[] {
  if (typeof field !== "string" || field.trim() === "") {
    throw new Error(`Empty or invalid value for field "${fieldName}"`);
  }

  const trimmed = field.trim();

  // Comma-separated list
  const parts = trimmed.split(",");
  if (parts.some((p) => p.trim() === "")) {
    throw new Error(
      `Empty segment in comma-separated list for field "${fieldName}": "${trimmed}"`
    );
  }

  const values = parts.flatMap((part) =>
    expandToken(part.trim(), min, max, fieldName)
  );

  return deduplicateAndSort(values);
}

/**
 * Parses a 5-field cron expression string into a structured object mapping
 * each field to an array of valid integer values it represents.
 *
 * Supported field syntax per position:
 *   - Wildcard:           *
 *   - Literal:            5
 *   - Range:              1-5
 *   - Step on wildcard:   * /15  (no space)
 *   - Step on range:      1-5/2
 *   - Step on start:      5/10
 *   - Comma list:         1,3,5 (combinable with the above)
 *
 * Field ranges:
 *   minute      0–59
 *   hour        0–23
 *   dayOfMonth  1–31
 *   month       1–12
 *   dayOfWeek   0–6  (0 = Sunday)
 *
 * @throws {TypeError}   if `expression` is not a string
 * @throws {Error}       if the expression has wrong field count or invalid syntax
 * @throws {RangeError}  if any value falls outside its valid range
 */
export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  // Reject any control characters or unexpected whitespace sequences
  if (/[\r\n\t\v\f]/.test(trimmed)) {
    throw new Error(
      `Cron expression contains invalid whitespace characters: "${trimmed}"`
    );
  }

  const fields = trimmed.split(/[ ]+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 space-separated fields, ` +
        `but got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const rawField = fields[i];
    result[fieldName] = expandField(rawField, FIELD_RANGES[fieldName], fieldName);
  }

  return result;
}

export default parseCron;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError("Capacity must be a positive integer");
    }
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      this.map.delete(this.map.keys().next().value as string);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  if (from > to) throw new Error(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseField(expr: string, field: keyof CronResult): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${expr}" for field "${field}"`);
    }
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${expr}" for field "${field}"`);
    }
    const base = parseField(rangePart, field);
    const start = base[0];
    return base.filter((v) => (v - start) % step === 0);
  }

  if (expr.includes("-")) {
    const [fromStr, toStr] = expr.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);
    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range "${expr}" for field "${field}"`);
    }
    assertInRange(from, min, max, field);
    assertInRange(to, min, max, field);
    return range(from, to);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${expr}" for field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

export default parseCron;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  },
] as const satisfies readonly FieldConfig[];

const INTEGER_RE = /^\d+$/;

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!INTEGER_RE.test(trimmed)) {
    throw new Error(`Invalid integer "${trimmed}" in ${context}`);
  }
  const value = parseInt(trimmed, 10);
  if (!Number.isSafeInteger(value)) {
    throw new Error(`Integer overflow "${trimmed}" in ${context}`);
  }
  return value;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range [${config.min}, ${config.max}] in ${context} (field: ${config.name})`
    );
  }
}

function expandRange(start: number, end: number, config: FieldConfig, context: string): number[] {
  assertInRange(start, config, context);
  assertInRange(end, config, context);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in ${context} (field: ${config.name})`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const ctx = `"${segment}" (field: ${config.name})`;

  // Step value: */n or start-end/n or start/n
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new Error(`Multiple "/" not allowed in ${ctx}`);
    }
    const slashIndex = segment.indexOf("/");
    const rangePart = segment.slice(0, slashIndex);
    const stepPart = segment.slice(slashIndex + 1);

    if (stepPart === "" || stepPart === "*") {
      throw new Error(`Invalid step value in ${ctx}`);
    }
    const step = parseInteger(stepPart, ctx);
    if (step <= 0) {
      throw new RangeError(`Step must be >= 1 in ${ctx}`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = config.min;
      rangeMax = config.max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr, ...extra] = rangePart.split("-");
      if (extra.length > 0) {
        throw new Error(`Multiple "-" in range part of ${ctx}`);
      }
      rangeMin = parseInteger(startStr ?? "", ctx);
      rangeMax = parseInteger(endStr ?? "", ctx);
      assertInRange(rangeMin, config, ctx);
      assertInRange(rangeMax, config, ctx);
      if (rangeMin > rangeMax) {
        throw new RangeError(`Range start ${rangeMin} exceeds end ${rangeMax} in ${ctx}`);
      }
    } else {
      rangeMin = parseInteger(rangePart, ctx);
      assertInRange(rangeMin, config, ctx);
      rangeMax = config.max;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let i = config.min; i <= config.max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr, ...extra] = segment.split("-");
    if (extra.length > 0) {
      throw new Error(`Multiple "-" not allowed in ${ctx}`);
    }
    if (!startStr || !endStr) {
      throw new Error(`Malformed range in ${ctx}`);
    }
    const start = parseInteger(startStr, ctx);
    const end = parseInteger(endStr, ctx);
    return expandRange(start, end, config, ctx);
  }

  // Single number
  const value = parseInteger(segment, ctx);
  assertInRange(value, config, ctx);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new Error(`Empty or invalid field for "${config.name}"`);
  }

  const segments = raw.split(",");
  if (segments.length === 0) {
    throw new Error(`No segments found in field "${config.name}"`);
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment (trailing/leading comma?) in field "${config.name}": "${raw}"`);
    }
    for (const value of parseSegment(trimmed, config)) {
      seen.add(value);
    }
  }

  return [...seen].sort((a, b) => a - b);
}

export default function parseCron(expression: unknown): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received: ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields as [
    string, string, string, string, string
  ];

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) values.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);
      const start = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const end = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);
      validateRange(start, min, max);
      validateRange(end, min, max);
      if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
      for (let i = start; i <= end; i += step) values.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = parseInt(rangeMatch[1], 10);
      const end = parseInt(rangeMatch[2], 10);
      validateRange(start, min, max);
      validateRange(end, min, max);
      if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
      for (let i = start; i <= end; i++) values.add(i);
      continue;
    }

    const numMatch = trimmed.match(/^(\d+)$/);
    if (numMatch) {
      const num = parseInt(numMatch[1], 10);
      validateRange(num, min, max);
      values.add(num);
      continue;
    }

    throw new Error(`Invalid cron field value: "${trimmed}"`);
  }

  return Array.from(values).sort((a, b) => a - b);
}

function validateRange(value: number, min: number, max: number): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }
}

function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const [minuteRange, hourRange, domRange, monthRange, dowRange] =
    fieldNames.map((name) => FIELD_RANGES[name]);

  const dayOfWeekRaw = parseField(dowStr, dowRange[0], dowRange[1]);
  // Normalize: both 0 and 7 represent Sunday; collapse to 0
  const dayOfWeek = Array.from(
    new Set(dayOfWeekRaw.map((d) => (d === 7 ? 0 : d)))
  ).sort((a, b) => a - b);

  return {
    minute: parseField(minuteStr, minuteRange[0], minuteRange[1]),
    hour: parseField(hourStr, hourRange[0], hourRange[1]),
    dayOfMonth: parseField(domStr, domRange[0], domRange[1]),
    month: parseField(monthStr, monthRange[0], monthRange[1]),
    dayOfWeek,
  };
}

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  }, // 0 and 7 both represent Sunday
] as const satisfies readonly FieldConfig[];

function assertInteger(raw: string, context: string): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "" || raw !== String(n)) {
    throw new RangeError(`Invalid integer "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range [${config.min}, ${config.max}] for field "${config.name}"`
    );
  }
}

function buildRange(start: number, end: number, step: number, config: FieldConfig): number[] {
  if (!Number.isInteger(step) || step < 1) {
    throw new RangeError(`Step must be a positive integer, got ${step} in field "${config.name}"`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must not exceed end (${end}) in field "${config.name}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseAtom(token: string, config: FieldConfig): number[] {
  const ctx = `field "${config.name}"`;

  // Step expression: "*/n", "a-b/n", or "a/n"
  if (token.includes("/")) {
    const slashIndex = token.lastIndexOf("/");
    const base = token.slice(0, slashIndex);
    const stepRaw = token.slice(slashIndex + 1);

    if (base === "" || stepRaw === "") {
      throw new SyntaxError(`Malformed step expression "${token}" in ${ctx}`);
    }

    const step = assertInteger(stepRaw, ctx);

    if (base === "*") {
      return buildRange(config.min, config.max, step, config);
    }

    if (base.includes("-")) {
      const dashIndex = base.indexOf("-");
      const start = assertInteger(base.slice(0, dashIndex), ctx);
      const end   = assertInteger(base.slice(dashIndex + 1), ctx);
      assertInRange(start, config);
      assertInRange(end,   config);
      return buildRange(start, end, step, config);
    }

    // Single-value base: treat as start, run to field max
    const start = assertInteger(base, ctx);
    assertInRange(start, config);
    return buildRange(start, config.max, step, config);
  }

  // Wildcard
  if (token === "*") {
    return buildRange(config.min, config.max, 1, config);
  }

  // Range: "a-b"
  if (token.includes("-")) {
    const dashIndex = token.indexOf("-");
    if (dashIndex === 0) {
      throw new SyntaxError(`Unexpected leading dash in "${token}" in ${ctx}`);
    }
    const start = assertInteger(token.slice(0, dashIndex), ctx);
    const end   = assertInteger(token.slice(dashIndex + 1), ctx);
    assertInRange(start, config);
    assertInRange(end,   config);
    return buildRange(start, end, 1, config);
  }

  // Single number
  const value = assertInteger(token, ctx);
  assertInRange(value, config);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new SyntaxError(`Field "${config.name}" must be a non-empty string`);
  }

  const atoms = raw.trim().split(",");
  if (atoms.some((a) => a.trim() === "")) {
    throw new SyntaxError(`Empty element in comma list for field "${config.name}"`);
  }

  const seen = new Set<number>();
  for (const atom of atoms) {
    for (const v of parseAtom(atom.trim(), config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, received ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

interface DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null;
  next: DLinkedNode<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLinkedNode<T>>;
  // Sentinel nodes: head = MRU side, tail = LRU side
  private readonly head: DLinkedNode<T>;
  private readonly tail: DLinkedNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 0) {
      throw new RangeError(`Capacity must be non-negative, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels carry no real data — cast is safe here
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) return undefined;

    // Promote to most-recently-used position
    this.detach(node);
    this.insertAfterHead(node);

    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache: accept calls but never store anything
    if (this.capacity === 0) return;

    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update in place and promote
      existing.value = value;
      this.detach(existing);
      this.insertAfterHead(existing);
      return;
    }

    // Evict LRU before inserting if at capacity
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;
      // Guard: should never be null given sentinels, but be explicit
      if (lru === null || lru === this.head) {
        throw new Error("LRUCache internal state is corrupted: no eviction candidate found");
      }
      this.detach(lru);
      this.map.delete(lru.key);
    }

    const node: DLinkedNode<T> = { key, value, prev: null, next: null };
    this.insertAfterHead(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  private detach(node: DLinkedNode<T>): void {
    const { prev, next } = node;
    // Both prev and next are always non-null for non-sentinel nodes
    if (prev === null || next === null) {
      throw new Error("LRUCache internal state is corrupted: detached node has null links");
    }
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertAfterHead(node: DLinkedNode<T>): void {
    const after = this.head.next;
    if (after === null) {
      throw new Error("LRUCache internal state is corrupted: head.next is null");
    }
    node.prev = this.head;
    node.next = after;
    this.head.next = node;
    after.prev = node;
  }
}

export default LRUCache;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseField(field: string, min: number, max: number): number[] {
  const allValues = range(min, max);

  // Wildcard
  if (field === "*") return allValues;

  // Step with wildcard: */n
  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return allValues.filter((v) => (v - min) % step === 0);
  }

  // Comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Range with optional step: a-b or a-b/n
  if (field.includes("-")) {
    const [rangePart, stepPart] = field.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || start > max) throw new RangeError(`Value ${start} out of range [${min}, ${max}]`);
    if (end < min || end > max) throw new RangeError(`Value ${end} out of range [${min}, ${max}]`);
    const rangeValues = range(start, end);
    if (stepPart !== undefined) {
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
      return rangeValues.filter((_, i) => i % step === 0);
    }
    return rangeValues;
  }

  // Single number
  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: ${field}`);
  if (num < min || num > max) throw new RangeError(`Value ${num} out of range [${min}, ${max}]`);
  return [num];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Cron expression must be a string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${parts.length}`);
  }

  const [minuteField, hourField, domField, monthField, dowField] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const fields = [minuteField, hourField, domField, monthField, dowField];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      throw new Error(`Error in field "${name}" ("${fields[i]}"): ${(err as Error).message}`);
    }
  }

  return result;
}

type Node<T> = {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
};

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (MRU side) and tail (LRU side) — never hold real data
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels remove all null-checks from hot-path operations
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError(
        "LRUCache does not accept undefined as a value — it is indistinguishable from a cache miss"
      );
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict before inserting so capacity is never exceeded even momentarily
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertAtFront(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Private helpers ───────────────────────────────────────────────────────

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null (at worst it is tail)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    // Both sentinels are always present, so prev/next are never null here
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Guard against the degenerate state of an empty list (only sentinels)
    if (lru === null || lru === this.head) {
      return;
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type PlainObject = Record<string, unknown>;
type FlattenedObject = Record<string, Primitive | unknown[]>;

const isPlainObject = (value: unknown): value is PlainObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  !(value instanceof Date) &&
  !(value instanceof RegExp) &&
  !(value instanceof Map) &&
  !(value instanceof Set) &&
  !(value instanceof ArrayBuffer) &&
  Object.getPrototypeOf(value) === Object.prototype;

const flattenObjectInternal = (
  obj: PlainObject,
  prefix: string,
  result: FlattenedObject,
  seen: WeakSet<object>
): void => {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0 && prefix !== "") {
    // Preserve empty objects as leaf values
    (result as Record<string, unknown>)[prefix] = {};
    seen.delete(obj);
    return;
  }

  for (const key of keys) {
    if (key === "") {
      throw new TypeError(
        `Empty string keys are not supported (found at prefix: "${prefix || "(root)"}")`
      );
    }

    const fullKey = prefix === "" ? key : `${prefix}.${key}`;
    const value: unknown = obj[key];

    if (isPlainObject(value)) {
      flattenObjectInternal(value, fullKey, result, seen);
    } else {
      (result as Record<string, unknown>)[fullKey] = value;
    }
  }

  seen.delete(obj);
};

const flattenObject = (input: unknown): FlattenedObject => {
  if (input === null || input === undefined) {
    throw new TypeError(
      `Expected a plain object but received: ${input === null ? "null" : "undefined"}`
    );
  }

  if (typeof input !== "object") {
    throw new TypeError(
      `Expected a plain object but received: ${typeof input}`
    );
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object but received an instance of: ${
        (input as object).constructor?.name ?? "unknown"
      }`
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  flattenObjectInternal(input, "", result, seen);

  return result;
};

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  7 }, // 0 and 7 both represent Sunday
] as const;

function toStrictInt(raw: string, label: string): number {
  // Number() rejects "1.5", " 3", "" more predictably than parseInt
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "") {
    throw new Error(`${label}: expected an integer, got "${raw}"`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Field "${config.name}" ${context}: value ${value} is outside valid range ` +
      `[${config.min}–${config.max}]`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseRangeBounds(token: string, config: FieldConfig): [number, number] {
  const dashIdx = token.indexOf("-");
  if (dashIdx <= 0 || dashIdx === token.length - 1) {
    throw new Error(
      `Field "${config.name}": malformed range "${token}" — expected "start-end"`
    );
  }

  const startStr = token.slice(0, dashIdx);
  const endStr   = token.slice(dashIdx + 1);

  if (endStr.includes("-")) {
    throw new Error(
      `Field "${config.name}": ambiguous range "${token}" — multiple dashes`
    );
  }

  const start = toStrictInt(startStr, `Field "${config.name}" range start`);
  const end   = toStrictInt(endStr,   `Field "${config.name}" range end`);

  assertInRange(start, config, "range start");
  assertInRange(end,   config, "range end");

  if (start > end) {
    throw new RangeError(
      `Field "${config.name}": range start ${start} must be ≤ end ${end}`
    );
  }

  return [start, end];
}

function parseToken(token: string, config: FieldConfig): number[] {
  if (token === "") {
    throw new Error(`Field "${config.name}": empty token`);
  }

  const slashCount = (token.match(/\//g) ?? []).length;
  if (slashCount > 1) {
    throw new Error(
      `Field "${config.name}": token "${token}" contains multiple "/" characters`
    );
  }

  // ── Step expression: */n  |  a-b/n  |  a/n ──────────────────────────────
  if (slashCount === 1) {
    const slashIdx  = token.indexOf("/");
    const rangePart = token.slice(0, slashIdx);
    const stepStr   = token.slice(slashIdx + 1);

    if (stepStr === "") {
      throw new Error(`Field "${config.name}": missing step value in "${token}"`);
    }

    const step = toStrictInt(stepStr, `Field "${config.name}" step`);
    if (step <= 0) {
      throw new RangeError(
        `Field "${config.name}": step must be a positive integer, got ${step}`
      );
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = config.min;
      rangeMax = config.max;
    } else if (rangePart.includes("-")) {
      [rangeMin, rangeMax] = parseRangeBounds(rangePart, config);
    } else {
      rangeMin = toStrictInt(rangePart, `Field "${config.name}" step start`);
      assertInRange(rangeMin, config, "step start");
      rangeMax = config.max;
    }

    return expandRange(rangeMin, rangeMax, step);
  }

  // ── Wildcard ─────────────────────────────────────────────────────────────
  if (token === "*") {
    return expandRange(config.min, config.max, 1);
  }

  // ── Range: a-b ───────────────────────────────────────────────────────────
  if (token.includes("-")) {
    const [start, end] = parseRangeBounds(token, config);
    return expandRange(start, end, 1);
  }

  // ── Single value ─────────────────────────────────────────────────────────
  const value = toStrictInt(token, `Field "${config.name}" value`);
  assertInRange(value, config, "value");
  return [value];
}

function parseField(expression: string, config: FieldConfig): number[] {
  if (expression === "") {
    throw new Error(`Field "${config.name}": expression must not be empty`);
  }

  const tokens = expression.split(",");

  if (tokens.some((t) => t.trim() === "")) {
    throw new Error(
      `Field "${config.name}": empty token in comma-separated list "${expression}"`
    );
  }

  const seen = new Set<number>();

  for (const token of tokens) {
    for (const v of parseToken(token.trim(), config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

/** Normalize dayOfWeek: both 0 and 7 represent Sunday; map 7 → 0. */
function normalizeDayOfWeek(values: number[]): number[] {
  const normalized = new Set<number>(
    values.map((v) => (v === 7 ? 0 : v))
  );
  return Array.from(normalized).sort((a, b) => a - b);
}

/**
 * Parse a 5-field cron expression into an object of concrete value arrays.
 *
 * Supported per field: "*", "n", "*/step", "a-b", "a-b/step", "a,b,c" (and combinations).
 *
 * Throws on invalid input, wrong field count, or out-of-range values.
 */
export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("parseCron: cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `parseCron: expected exactly 5 fields, got ${fields.length} in "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields as [
    string, string, string, string, string
  ];

  return {
    minute:     parseField(minuteExpr, FIELD_CONFIGS[0]),
    hour:       parseField(hourExpr,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domExpr,    FIELD_CONFIGS[2]),
    month:      parseField(monthExpr,  FIELD_CONFIGS[3]),
    dayOfWeek:  normalizeDayOfWeek(parseField(dowExpr, FIELD_CONFIGS[4])),
  };
}

interface DoublyLinkedNode<T> {
  key: string;
  value: T;
  prev: DoublyLinkedNode<T> | null;
  next: DoublyLinkedNode<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DoublyLinkedNode<T>>;
  private head: DoublyLinkedNode<T>; // sentinel: most recently used side
  private tail: DoublyLinkedNode<T>; // sentinel: least recently used side

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes eliminate null-edge-case branches in insert/remove
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError(
        "Cannot store undefined as a cache value; use null to represent absence"
      );
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: DoublyLinkedNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }
    return this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Private helpers ──────────────────────────────────────────────────────

  private insertAtFront(node: DoublyLinkedNode<T>): void {
    // Place node immediately after head sentinel (most-recently-used position)
    node.prev = this.head;
    node.next = this.head.next;

    // head.next is always non-null (at minimum it points to tail sentinel)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: DoublyLinkedNode<T>): void {
    // Sentinels guarantee prev/next are never null for real nodes
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DoublyLinkedNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    // The node immediately before the tail sentinel is the least-recently-used
    const lru = this.tail.prev;

    // Guard: if lru is the head sentinel the cache is somehow empty — do nothing
    if (lru === null || lru === this.head) {
      return;
    }

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  result: FlattenedObject = {},
  seen = new WeakSet<object>()
): FlattenedObject {
  if (!isPlainObject(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (seen.has(input)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  const keys = Object.keys(input);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = input as unknown as Primitive;
    }
    return result;
  }

  seen.add(input);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const sanitizedKey = key.replace(/\./g, "\\.");
    const newPrefix = prefix === "" ? sanitizedKey : `${prefix}.${sanitizedKey}`;
    const value = input[key];

    if (isPlainObject(value)) {
      const nestedKeys = Object.keys(value);
      if (nestedKeys.length === 0) {
        result[newPrefix] = value as unknown as Primitive;
      } else {
        flattenObject(value, newPrefix, result, seen);
      }
    } else {
      result[newPrefix] = value as Primitive;
    }
  }

  seen.delete(input);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : String(index);
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;
type FlattenedObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenRecursive(
  obj: PlainObject,
  prefix: string,
  result: FlattenedObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at path "${prefix || "<root>"}"`
    );
  }

  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value: unknown = obj[key];

    if (isPlainObject(value)) {
      const childKeys = Object.keys(value);
      if (childKeys.length === 0) {
        // Preserve empty objects as leaf values so no information is silently dropped
        result[fullKey] = value;
      } else {
        flattenRecursive(value, fullKey, result, ancestors);
      }
    } else {
      result[fullKey] = value;
    }
  }

  ancestors.delete(obj);
}

function flattenObject(obj: PlainObject): FlattenedObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlattenedObject = {};
  flattenRecursive(obj, "", result, new WeakSet<object>());
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { maxDepth?: number; prefix?: string } = {}
): FlattenedObject {
  const { maxDepth = 100, prefix = "" } = options;

  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${Array.isArray(input) ? "array" : typeof input}`
    );
  }

  const result: FlattenedObject = {};

  function recurse(current: Record<string, unknown>, currentPrefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    const keys = Object.keys(current);

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const fullKey = currentPrefix.length > 0 ? `${currentPrefix}.${key}` : key;
      const value = current[key];

      if (isPlainObject(value)) {
        const nestedKeys = Object.keys(value);

        if (nestedKeys.length === 0) {
          // Preserve empty objects as empty-string sentinel? No — emit nothing.
          // An empty nested object contributes no leaf values.
          continue;
        }

        recurse(value, fullKey, depth + 1);
      } else if (Array.isArray(value)) {
        // Arrays are not plain objects — treat as leaf values to avoid silent data loss.
        // Callers who want array flattening should pre-process their input.
        (result as Record<string, unknown>)[fullKey] = value;
      } else {
        result[fullKey] = value as Primitive;
      }
    }
  }

  recurse(input, prefix, 0);

  return result;
}

export default flattenObject;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  readonly name: keyof CronResult;
  readonly min: number;
  readonly max: number;
};

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const;

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInRange(value: number, min: number, max: number, fieldName: string, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Field "${fieldName}": value ${value} is out of valid range [${min}-${max}] in "${context}"`
    );
  }
}

function parseSingleValue(raw: string, config: FieldConfig): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "") {
    throw new TypeError(`Field "${config.name}": cannot parse "${raw}" as integer`);
  }
  assertInRange(n, config.min, config.max, config.name, raw);
  return n;
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  if (raw === "") {
    throw new SyntaxError(`Field "${name}": empty field expression`);
  }

  // Wildcard — expand to full valid range
  if (raw === "*") {
    return buildRange(min, max);
  }

  // Step expression: */N  (only wildcard-based steps supported per spec)
  const stepMatch = /^\*\/(\d+)$/.exec(raw);
  if (stepMatch !== null) {
    const step = Number(stepMatch[1]);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Field "${name}": step must be a positive integer, got "${stepMatch[1]}" in "${raw}"`);
    }
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    if (values.length === 0) {
      throw new RangeError(`Field "${name}": step ${step} produces no values within [${min}-${max}]`);
    }
    return values;
  }

  // Range expression: N-M
  const rangeMatch = /^(\d+)-(\d+)$/.exec(raw);
  if (rangeMatch !== null) {
    const start = Number(rangeMatch[1]);
    const end   = Number(rangeMatch[2]);
    assertInRange(start, min, max, name, raw);
    assertInRange(end,   min, max, name, raw);
    if (start > end) {
      throw new RangeError(
        `Field "${name}": range start (${start}) must not exceed range end (${end}) in "${raw}"`
      );
    }
    return buildRange(start, end);
  }

  // Comma-separated list: only plain integers per spec
  if (raw.includes(",")) {
    // Guard against trailing/leading commas or consecutive commas
    if (/^,|,$|,,/.test(raw)) {
      throw new SyntaxError(`Field "${name}": malformed comma-separated list "${raw}"`);
    }
    const parts = raw.split(",");
    const values = parts.map(part => parseSingleValue(part, config));
    // Deduplicate and sort to give a clean, predictable result
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single integer
  return [parseSingleValue(raw, config)];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("parseCron received an empty cron expression");
  }

  // Split on any run of whitespace; guard against unexpected separators
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `but "${trimmed}" has ${fields.length}`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    // Any parse failure surfaces immediately with field context intact
    result[config.name] = parseField(fields[i], config);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly [FieldConfig, FieldConfig, FieldConfig, FieldConfig, FieldConfig] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

const DIGITS_ONLY = /^\d+$/;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] ${context}`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  config: FieldConfig
): number[] {
  assertInRange(start, config.min, config.max, `(range start in field "${config.name}")`);
  assertInRange(end,   config.min, config.max, `(range end in field "${config.name}")`);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} must not exceed range end ${end} in field "${config.name}"`
    );
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseStep(stepStr: string, fieldName: string): number {
  if (!DIGITS_ONLY.test(stepStr)) {
    throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
  }
  const step = parseInt(stepStr, 10);
  if (step <= 0) {
    throw new RangeError(
      `Step value must be a positive integer, got ${step} in field "${fieldName}"`
    );
  }
  return step;
}

function parseSegment(raw: string, config: FieldConfig): number[] {
  if (raw === "") {
    throw new SyntaxError(`Empty segment encountered in field "${config.name}"`);
  }

  // ── Step expression: base/step ───────────────────────────────────────────
  const slashIdx = raw.indexOf("/");
  if (slashIdx !== -1) {
    const base    = raw.slice(0, slashIdx);
    const stepStr = raw.slice(slashIdx + 1);

    if (base === "") {
      throw new SyntaxError(`Missing base before "/" in field "${config.name}"`);
    }
    if (stepStr === "") {
      throw new SyntaxError(`Missing step after "/" in field "${config.name}"`);
    }

    const step = parseStep(stepStr, config.name);

    if (base === "*") {
      return expandRange(config.min, config.max, step, config);
    }

    const dashIdx = base.indexOf("-");
    if (dashIdx !== -1) {
      const startStr = base.slice(0, dashIdx);
      const endStr   = base.slice(dashIdx + 1);

      if (!DIGITS_ONLY.test(startStr) || !DIGITS_ONLY.test(endStr)) {
        throw new SyntaxError(
          `Invalid range "${base}" in step expression in field "${config.name}"`
        );
      }

      return expandRange(parseInt(startStr, 10), parseInt(endStr, 10), step, config);
    }

    if (!DIGITS_ONLY.test(base)) {
      throw new SyntaxError(
        `Invalid base "${base}" in step expression in field "${config.name}"`
      );
    }

    const start = parseInt(base, 10);
    assertInRange(start, config.min, config.max, `(step base in field "${config.name}")`);
    return expandRange(start, config.max, step, config);
  }

  // ── Wildcard ─────────────────────────────────────────────────────────────
  if (raw === "*") {
    return expandRange(config.min, config.max, 1, config);
  }

  // ── Range: start-end ─────────────────────────────────────────────────────
  const dashIdx = raw.indexOf("-");
  if (dashIdx !== -1) {
    const startStr = raw.slice(0, dashIdx);
    const endStr   = raw.slice(dashIdx + 1);

    if (!DIGITS_ONLY.test(startStr) || !DIGITS_ONLY.test(endStr)) {
      throw new SyntaxError(`Invalid range "${raw}" in field "${config.name}"`);
    }

    return expandRange(parseInt(startStr, 10), parseInt(endStr, 10), 1, config);
  }

  // ── Single number ────────────────────────────────────────────────────────
  if (!DIGITS_ONLY.test(raw)) {
    throw new SyntaxError(
      `Unexpected token "${raw}" in field "${config.name}"; expected a number, range, step, or "*"`
    );
  }

  const value = parseInt(raw, 10);
  assertInRange(value, config.min, config.max, `(in field "${config.name}")`);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new SyntaxError(`Field "${config.name}" must be a non-empty string`);
  }

  const segments = raw.trim().split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(
        `Empty segment in comma-separated list for field "${config.name}"`
      );
    }
    for (const v of parseSegment(trimmed, config)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(`Field "${config.name}" produced no valid values`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty or whitespace-only");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 space-separated fields, ` +
      `got ${fields.length}: "${expression}"`
    );
  }

  return {
    minute:     parseField(fields[0], FIELD_CONFIGS[0]),
    hour:       parseField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    month:      parseField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(fields[4], FIELD_CONFIGS[4]),
  };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object"
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.promoteToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove entries");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.promoteToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  private insertAtHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private promoteToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.insertAtHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject | Array<unknown>,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : String(index);
        if (item !== null && typeof item === "object") {
          flattenObject(item as NestedObject, key, result);
        } else {
          result[key] = item as Primitive;
        }
      });
    }
    return result;
  }

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value === null || value === undefined) {
      result[newKey] = value;
    } else if (Array.isArray(value)) {
      flattenObject(value, newKey, result);
    } else if (typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("LRUCache does not accept undefined as a value");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head;
    while (current !== null) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private prependHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) {
      return;
    }
    this.removeNode(node);
    this.prependHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) {
      return;
    }
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type PlainObject = Record<string, unknown>;
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: PlainObject,
  prefix: string,
  result: FlatObject,
  seen: Set<object>
): void {
  if (seen.has(obj)) {
    // Circular reference: record sentinel rather than infinite-loop
    result[prefix] = "[Circular]";
    return;
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty-object leaves so callers know the key existed
    if (prefix !== "") {
      result[prefix] = {};
    }
    seen.delete(obj);
    return;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const fullKey = prefix !== "" ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      flattenObjectInternal(value, fullKey, result, seen);
    } else {
      result[fullKey] = value;
    }
  }

  // Remove on the way out so the same object can appear in sibling branches
  // without being falsely flagged as a cycle
  seen.delete(obj);
}

export default function flattenObject(obj: PlainObject): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flattenObjectInternal(obj, "", result, new Set());
  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: Array<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseNumber(token: string, context: string): number {
  const trimmed = token.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(`Expected a number but got "${trimmed}" in field "${context}"`);
  }
  return parseInt(trimmed, 10);
}

function expandWildcard(config: FieldConfig): number[] {
  const values: number[] = [];
  for (let i = config.min; i <= config.max; i++) {
    values.push(i);
  }
  return values;
}

function expandStep(token: string, config: FieldConfig, context: string): number[] {
  const [basePart, stepPart] = token.split("/");

  if (stepPart === undefined || stepPart.trim() === "") {
    throw new SyntaxError(`Missing step value after "/" in field "${context}"`);
  }

  const step = parseNumber(stepPart, context);
  if (step <= 0) {
    throw new RangeError(`Step value must be positive, got ${step} in field "${context}"`);
  }

  let rangeMin: number;
  let rangeMax: number;

  if (basePart.trim() === "*") {
    rangeMin = config.min;
    rangeMax = config.max;
  } else if (basePart.includes("-")) {
    [rangeMin, rangeMax] = parseRange(basePart, config, context);
  } else {
    rangeMin = parseNumber(basePart, context);
    assertInRange(rangeMin, config.min, config.max, context);
    rangeMax = config.max;
  }

  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    values.push(i);
  }

  if (values.length === 0) {
    throw new RangeError(`Step expression "${token}" produces no values in field "${context}"`);
  }

  return values;
}

function parseRange(token: string, config: FieldConfig, context: string): [number, number] {
  const parts = token.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(`Invalid range "${token}" in field "${context}"`);
  }

  const start = parseNumber(parts[0], context);
  const end = parseNumber(parts[1], context);

  assertInRange(start, config.min, config.max, context);
  assertInRange(end, config.min, config.max, context);

  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must not exceed range end (${end}) in field "${context}"`
    );
  }

  return [start, end];
}

function expandRange(token: string, config: FieldConfig, context: string): number[] {
  const [start, end] = parseRange(token, config, context);
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function parseSegment(token: string, config: FieldConfig, context: string): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty segment encountered in field "${context}"`);
  }

  if (trimmed === "*") {
    return expandWildcard(config);
  }

  if (trimmed.includes("/")) {
    return expandStep(trimmed, config, context);
  }

  if (trimmed.includes("-")) {
    return expandRange(trimmed, config, context);
  }

  const value = parseNumber(trimmed, context);
  assertInRange(value, config.min, config.max, context);
  return [value];
}

function parseField(expression: string, config: FieldConfig, context: string): number[] {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new SyntaxError(`Field "${context}" must be a non-empty string`);
  }

  const segments = expression.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const expanded = parseSegment(segment, config, context);
    for (const v of expanded) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(parts[i], config, fieldName);
  }

  return result;
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

const EXPECTED_FIELD_COUNT = 5;

function assertInteger(value: number, context: string): void {
  if (!Number.isInteger(value)) {
    throw new RangeError(`${context}: expected an integer, got ${value}`);
  }
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  assertInteger(value, context);
  if (value < min || value > max) {
    throw new RangeError(
      `${context}: value ${value} is out of valid range [${min}, ${max}]`
    );
  }
}

function parseNumber(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new SyntaxError(`${context}: "${trimmed}" is not a valid integer`);
  }
  return Number(trimmed);
}

function expandAll(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function expandStep(base: number[], step: number, context: string): number[] {
  assertInteger(step, `${context} step`);
  if (step <= 0) {
    throw new RangeError(`${context}: step value must be >= 1, got ${step}`);
  }
  return base.filter((_, i) => i % step === 0);
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  const context = `field "${fieldName}", segment "${segment}"`;

  // Step expression: something/N
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(`${context}: multiple "/" characters are not allowed`);
    }

    const [basePart, stepPart] = segment.split("/");
    if (stepPart === "" || stepPart === undefined) {
      throw new SyntaxError(`${context}: missing step value after "/"`);
    }

    const step = parseNumber(stepPart, `${context} step`);

    let base: number[];
    if (basePart === "*") {
      base = expandAll(min, max);
    } else if (basePart.includes("-")) {
      base = parseRange(basePart, min, max, fieldName);
    } else {
      const start = parseNumber(basePart, context);
      assertInRange(start, min, max, context);
      base = expandAll(start, max);
    }

    return expandStep(base, step, context);
  }

  // Range expression: N-M
  if (segment.includes("-")) {
    return parseRange(segment, min, max, fieldName);
  }

  // Wildcard
  if (segment === "*") {
    return expandAll(min, max);
  }

  // Plain number
  const value = parseNumber(segment, context);
  assertInRange(value, min, max, context);
  return [value];
}

function parseRange(raw: string, min: number, max: number, fieldName: string): number[] {
  const context = `field "${fieldName}", range "${raw}"`;
  const dashCount = (raw.match(/-/g) ?? []).length;
  if (dashCount !== 1) {
    throw new SyntaxError(`${context}: expected exactly one "-" in a range`);
  }

  const [startPart, endPart] = raw.split("-");
  if (startPart === "" || endPart === "" || startPart === undefined || endPart === undefined) {
    throw new SyntaxError(`${context}: range start or end is missing`);
  }

  const start = parseNumber(startPart, `${context} start`);
  const end = parseNumber(endPart, `${context} end`);

  assertInRange(start, min, max, `${context} start`);
  assertInRange(end, min, max, `${context} end`);

  if (start > end) {
    throw new RangeError(
      `${context}: range start (${start}) must be <= range end (${end})`
    );
  }

  return expandAll(start, end);
}

function deduplicateAndSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  if (raw === undefined || raw.trim() === "") {
    throw new SyntaxError(`field "${name}": field value is empty or undefined`);
  }

  const segments = raw.split(",");

  if (segments.length === 0) {
    throw new SyntaxError(`field "${name}": no segments found`);
  }

  const collected: number[] = [];

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(
        `field "${name}": empty segment in comma-separated list "${raw}"`
      );
    }
    const values = parseSegment(trimmed, min, max, name);
    for (const v of values) collected.push(v);
  }

  return deduplicateAndSort(collected);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("parseCron: expression is empty");
  }

  // Split on whitespace sequences; guard against leading/trailing whitespace
  const fields = trimmed.split(/\s+/);

  if (fields.length !== EXPECTED_FIELD_COUNT) {
    throw new SyntaxError(
      `parseCron: expected ${EXPECTED_FIELD_COUNT} fields, got ${fields.length} in "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = fields;

  return {
    minute: parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour: parseField(hourRaw, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS[2]),
    month: parseField(monthRaw, FIELD_CONFIGS[3]),
    dayOfWeek: parseField(dayOfWeekRaw, FIELD_CONFIGS[4]),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
] as const satisfies FieldConfig[];

function assertInteger(raw: string, fieldName: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new SyntaxError(
      `Field "${fieldName}": "${raw}" is not a valid non-negative integer`
    );
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, config: FieldConfig): number {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Field "${config.name}": value ${value} is out of valid range [${config.min}–${config.max}]`
    );
  }
  return value;
}

function expandRange(raw: string, config: FieldConfig): [number, number] {
  const dashIdx = raw.indexOf("-");
  const startRaw = raw.slice(0, dashIdx).trim();
  const endRaw   = raw.slice(dashIdx + 1).trim();

  if (!startRaw || !endRaw) {
    throw new SyntaxError(
      `Field "${config.name}": malformed range "${raw}"`
    );
  }

  const start = assertInRange(assertInteger(startRaw, config.name), config);
  const end   = assertInRange(assertInteger(endRaw,   config.name), config);

  if (start > end) {
    throw new RangeError(
      `Field "${config.name}": range start ${start} exceeds end ${end}`
    );
  }

  return [start, end];
}

/**
 * Parses a single token (no commas) — handles *, number, range, step.
 */
function parseToken(token: string, config: FieldConfig): number[] {
  const trimmed = token.trim();

  if (!trimmed) {
    throw new SyntaxError(`Field "${config.name}": empty token`);
  }

  // ── Step form: base/step ────────────────────────────────────────────────
  if (trimmed.includes("/")) {
    const slashIdx = trimmed.lastIndexOf("/");
    const baseRaw  = trimmed.slice(0, slashIdx).trim();
    const stepRaw  = trimmed.slice(slashIdx + 1).trim();

    if (!baseRaw || !stepRaw) {
      throw new SyntaxError(
        `Field "${config.name}": malformed step expression "${trimmed}"`
      );
    }

    const step = assertInteger(stepRaw, config.name);
    if (step <= 0) {
      throw new RangeError(
        `Field "${config.name}": step value must be ≥ 1, got ${step}`
      );
    }

    let rangeMin = config.min;
    let rangeMax = config.max;

    if (baseRaw === "*") {
      rangeMin = config.min;
      rangeMax = config.max;
    } else if (baseRaw.includes("-")) {
      [rangeMin, rangeMax] = expandRange(baseRaw, config);
    } else {
      rangeMin = assertInRange(assertInteger(baseRaw, config.name), config);
      rangeMax = config.max;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) values.push(i);
    return values;
  }

  // ── Wildcard ────────────────────────────────────────────────────────────
  if (trimmed === "*") {
    const values: number[] = [];
    for (let i = config.min; i <= config.max; i++) values.push(i);
    return values;
  }

  // ── Range ───────────────────────────────────────────────────────────────
  if (trimmed.includes("-")) {
    const [start, end] = expandRange(trimmed, config);
    const values: number[] = [];
    for (let i = start; i <= end; i++) values.push(i);
    return values;
  }

  // ── Single integer ──────────────────────────────────────────────────────
  return [assertInRange(assertInteger(trimmed, config.name), config)];
}

/**
 * Parses one cron field, supporting comma-separated lists where each element
 * may itself be a number, wildcard, range, or step expression.
 */
function parseField(field: string, config: FieldConfig): number[] {
  if (typeof field !== "string" || !field.trim()) {
    throw new SyntaxError(`Field "${config.name}": received empty or non-string value`);
  }

  const parts = field.split(",");
  const seen  = new Set<number>();

  for (const part of parts) {
    if (!part.trim()) {
      throw new SyntaxError(
        `Field "${config.name}": empty segment in comma-separated list "${field}"`
      );
    }
    for (const value of parseToken(part, config)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

/**
 * Parses a 5-field cron expression into structured arrays of resolved values.
 *
 * Supported field syntax: `*`, number, `*\/step`, `start-end`, `start-end/step`,
 * and comma-separated combinations of the above.
 *
 * @throws {TypeError}   if `expression` is not a string
 * @throws {SyntaxError} if the expression is malformed
 * @throws {RangeError}  if any value falls outside its valid range
 */
export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expected a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError("parseCron: expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `parseCron: expected exactly 5 whitespace-separated fields, got ${fields.length} in "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }

    if (start < min || end > max || start > end) {
      throw new Error(
        `Range ${start}-${end} out of bounds [${min}, ${max}]`
      );
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }

    if (start < min || end > max || start > end) {
      throw new Error(
        `Range ${start}-${end} out of bounds [${min}, ${max}]`
      );
    }

    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value: ${field}`);
  }

  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
  }

  return [value];
}

export default function parseCron(expression: string): CronFields {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteStr,
    hourStr,
    dayOfMonthStr,
    monthStr,
    dayOfWeekStr,
  ].map((fieldStr, index) => {
    const name = fieldNames[index];
    const [min, max] = FIELD_RANGES[name];
    try {
      return parseField(fieldStr, min, max);
    } catch (err) {
      throw new Error(
        `Invalid ${name} field "${fieldStr}": ${(err as Error).message}`
      );
    }
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependToHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  private prependToHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    const { prev, next } = node;

    if (prev !== null) {
      prev.next = next;
    } else {
      this.head = next;
    }

    if (next !== null) {
      next.prev = prev;
    } else {
      this.tail = prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) {
      return;
    }
    this.removeNode(node);
    this.prependToHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) {
      return;
    }
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInternal(
  obj: PlainObject,
  prefix: string,
  ancestors: Set<object>,
  result: PlainObject
): void {
  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      if (ancestors.has(value)) {
        // Circular reference detected — skip to avoid infinite recursion
        continue;
      }
      ancestors.add(value);
      flattenInternal(value, fullKey, ancestors, result);
      ancestors.delete(value); // Remove on exit so shared refs aren't falsely flagged
    } else {
      result[fullKey] = value;
    }
  }
}

export default function flattenObject(obj: PlainObject): PlainObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject: expected a plain object, got ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: PlainObject = {};
  const ancestors = new Set<object>([obj]);
  flattenInternal(obj, "", ancestors, result);
  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlattenedObject = {},
  seen: WeakSet<object> = new WeakSet()
): FlattenedObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as null | undefined;
    }
    return result;
  }

  if (typeof input !== "object" && !Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input === "object") {
    if (seen.has(input as object)) {
      throw new Error(
        `Circular reference detected at key: "${prefix}"`
      );
    }
    seen.add(input as object);
  }

  if (Array.isArray(input)) {
    if (input.length === 0 && prefix !== "") {
      result[prefix] = undefined;
    } else {
      for (let i = 0; i < input.length; i++) {
        const key = prefix !== "" ? `${prefix}.${i}` : `${i}`;
        flattenObject(input[i], key, result, seen);
      }
    }
    return result;
  }

  const obj = input as Record<string, unknown>;
  const keys = Object.keys(obj);

  if (keys.length === 0 && prefix !== "") {
    result[prefix] = undefined;
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const sanitizedKey = key.replace(/\./g, "\\.");
    const newKey = prefix !== "" ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, newKey, result, seen);
    } else if (Array.isArray(value)) {
      flattenObject(value, newKey, result, seen);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new Error("Capacity must be a positive integer");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key)!;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value;
      if (lruKey !== undefined) this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    if (!this.cache.has(key)) {
      return undefined;
    }

    // Refresh recency: delete and re-insert to move to end of insertion order
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError(
        "Cache value must not be undefined; use delete() to remove entries"
      );
    }

    if (this.cache.has(key)) {
      // Update existing: remove first so re-insertion moves it to most-recent
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Evict the least-recently-used entry (first key in Map insertion order)
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }
    return this.cache.delete(key);
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }
    return this.cache.has(key);
  }

  clear(): void {
    this.cache.clear();
  }

  get size(): number {
    return this.cache.size;
  }
}

export default LRUCache;

type LeafValue = unknown;
type FlattenedObject = Record<string, LeafValue>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: Record<string, unknown>,
  prefix: string,
  seen: WeakSet<object>,
  result: FlattenedObject
): void {
  if (seen.has(obj)) return;
  seen.add(obj);

  for (const key of Object.keys(obj)) {
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value)) {
      if (seen.has(value)) {
        // Circular reference: surface it as a leaf rather than looping infinitely
        result[fullKey] = "[Circular]";
      } else {
        // Recurse into nested plain objects; empty objects produce no keys (by design)
        flattenObjectInternal(value, fullKey, seen, result);
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove after processing so the same object reference can appear
  // in multiple non-circular branches without false positive detection
  seen.delete(obj);
}

export default function flattenObject(obj: Record<string, unknown>): FlattenedObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object at the root; received ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlattenedObject = {};
  flattenObjectInternal(obj, "", new WeakSet(), result);
  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  7 }, // 0 and 7 both represent Sunday in many implementations
] as const;

function parseNonNegativeInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new Error(`Empty integer value in ${context}`);
  }
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected an integer but got "${trimmed}" in ${context}`);
  }
  const n = Number(trimmed);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new Error(`Non-finite or non-integer value "${trimmed}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is outside the valid range [${min}, ${max}] in ${context}`
    );
  }
}

function buildSequence(start: number, end: number, step: number, context: string): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must not exceed end (${end}) in ${context}`
    );
  }
  if (step < 1) {
    throw new RangeError(`Step must be >= 1 but got ${step} in ${context}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;
  const trimmed = segment.trim();
  const context = `field "${name}"`;

  if (trimmed === "") {
    throw new Error(`Empty segment in ${context}`);
  }

  // Detect a step suffix: "*/N", "A-B/N", or "A/N"
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.lastIndexOf("/");
    const beforeSlash = trimmed.slice(0, slashIndex);
    const afterSlash  = trimmed.slice(slashIndex + 1);

    if (beforeSlash === "" || afterSlash === "") {
      throw new Error(`Malformed step expression "${trimmed}" in ${context}`);
    }

    const step = parseNonNegativeInteger(afterSlash, `${context} step`);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1 but got ${step} in ${context}`);
    }

    if (beforeSlash === "*") {
      return buildSequence(min, max, step, context);
    }

    if (beforeSlash.includes("-")) {
      const dashParts = beforeSlash.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Invalid range "${beforeSlash}" in ${context}`);
      }
      const start = parseNonNegativeInteger(dashParts[0], context);
      const end   = parseNonNegativeInteger(dashParts[1], context);
      assertInRange(start, min, max, context);
      assertInRange(end,   min, max, context);
      return buildSequence(start, end, step, context);
    }

    // "N/step" — start from N and step to max
    const start = parseNonNegativeInteger(beforeSlash, context);
    assertInRange(start, min, max, context);
    return buildSequence(start, max, step, context);
  }

  // Wildcard — expand to all valid values
  if (trimmed === "*") {
    return buildSequence(min, max, 1, context);
  }

  // Range: "A-B"
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new Error(
        `Invalid range "${trimmed}" in ${context}; only one hyphen is allowed`
      );
    }
    const start = parseNonNegativeInteger(dashParts[0], context);
    const end   = parseNonNegativeInteger(dashParts[1], context);
    assertInRange(start, min, max, context);
    assertInRange(end,   min, max, context);
    return buildSequence(start, end, 1, context);
  }

  // Single integer value
  const value = parseNonNegativeInteger(trimmed, context);
  assertInRange(value, min, max, context);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw === undefined || raw === null) {
    throw new Error(`Missing value for field "${config.name}"`);
  }
  if (typeof raw !== "string") {
    throw new TypeError(
      `Field "${config.name}" must be a string, got ${typeof raw}`
    );
  }

  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new Error(`Field "${config.name}" must not be blank`);
  }

  const segments = trimmed.split(",");
  const seen = new Set<number>();

  for (let i = 0; i < segments.length; i++) {
    const seg = segments[i].trim();
    if (seg === "") {
      throw new Error(
        `Empty segment at position ${i} in comma-separated list for field "${config.name}"`
      );
    }
    for (const v of parseSegment(seg, config)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new Error(`No valid values resolved for field "${config.name}"`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (expression === undefined || expression === null) {
    throw new TypeError(
      `parseCron expects a string but received ${expression}`
    );
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string but received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty or blank");
  }

  // Split on one-or-more whitespace characters to tolerate extra spacing
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must contain exactly 5 space-separated fields ` +
      `(minute hour dayOfMonth month dayOfWeek), but got ${fields.length} ` +
      `field(s) in: "${trimmed}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new CronParseError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseInteger(token: string, context: string): number {
  const trimmed = token.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new CronParseError(
      `Expected an integer but got "${trimmed}" in field "${context}"`
    );
  }
  return parseInt(trimmed, 10);
}

function expandRange(
  raw: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  const parts = raw.split("-");
  if (parts.length !== 2) {
    throw new CronParseError(
      `Invalid range "${raw}" in field "${fieldName}"`
    );
  }
  const start = parseInteger(parts[0], fieldName);
  const end = parseInteger(parts[1], fieldName);
  assertInRange(start, config.min, config.max, fieldName);
  assertInRange(end, config.min, config.max, fieldName);
  if (start > end) {
    throw new CronParseError(
      `Range start ${start} is greater than end ${end} in field "${fieldName}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function expandStep(
  raw: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  const [basePart, stepPart, ...extra] = raw.split("/");
  if (extra.length > 0 || stepPart === undefined || stepPart.trim() === "") {
    throw new CronParseError(
      `Invalid step expression "${raw}" in field "${fieldName}"`
    );
  }
  const step = parseInteger(stepPart, fieldName);
  if (step <= 0) {
    throw new CronParseError(
      `Step value must be a positive integer, got ${step} in field "${fieldName}"`
    );
  }

  let rangeMin: number;
  let rangeMax: number;

  if (basePart.trim() === "*") {
    rangeMin = config.min;
    rangeMax = config.max;
  } else if (basePart.includes("-")) {
    const rangeParts = basePart.split("-");
    if (rangeParts.length !== 2) {
      throw new CronParseError(
        `Invalid base range "${basePart}" in step expression "${raw}" in field "${fieldName}"`
      );
    }
    rangeMin = parseInteger(rangeParts[0], fieldName);
    rangeMax = parseInteger(rangeParts[1], fieldName);
    assertInRange(rangeMin, config.min, config.max, fieldName);
    assertInRange(rangeMax, config.min, config.max, fieldName);
    if (rangeMin > rangeMax) {
      throw new CronParseError(
        `Range start ${rangeMin} is greater than end ${rangeMax} in field "${fieldName}"`
      );
    }
  } else {
    rangeMin = parseInteger(basePart, fieldName);
    assertInRange(rangeMin, config.min, config.max, fieldName);
    rangeMax = config.max;
  }

  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    values.push(i);
  }
  if (values.length === 0) {
    throw new CronParseError(
      `Step expression "${raw}" produced no values in field "${fieldName}"`
    );
  }
  return values;
}

function parseSegment(
  segment: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  const trimmed = segment.trim();
  if (trimmed === "") {
    throw new CronParseError(`Empty segment in field "${fieldName}"`);
  }

  // Wildcard
  if (trimmed === "*") {
    const values: number[] = [];
    for (let i = config.min; i <= config.max; i++) {
      values.push(i);
    }
    return values;
  }

  // Step expression (contains "/")
  if (trimmed.includes("/")) {
    return expandStep(trimmed, config, fieldName);
  }

  // Range (contains "-")
  if (trimmed.includes("-")) {
    return expandRange(trimmed, config, fieldName);
  }

  // Plain number
  const value = parseInteger(trimmed, fieldName);
  assertInRange(value, config.min, config.max, fieldName);
  return [value];
}

function parseField(
  raw: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new CronParseError(`Missing or empty value for field "${fieldName}"`);
  }

  const segments = raw.split(",");
  if (segments.length === 0) {
    throw new CronParseError(`No segments found in field "${fieldName}"`);
  }

  const collected = new Set<number>();
  for (const segment of segments) {
    const values = parseSegment(segment, config, fieldName);
    for (const v of values) {
      collected.add(v);
    }
  }

  const result = Array.from(collected).sort((a, b) => a - b);

  // Normalise dayOfWeek: treat 7 as Sunday (0) per POSIX convention
  if (fieldName === "dayOfWeek") {
    const normalised = new Set<number>();
    for (const v of result) {
      normalised.add(v === 7 ? 0 : v);
    }
    return Array.from(normalised).sort((a, b) => a - b);
  }

  return result;
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  // Collapse multiple whitespace characters into a single space
  const normalized = trimmed.replace(/\s+/g, " ");
  const parts = normalized.split(" ");

  if (parts.length !== 5) {
    throw new CronParseError(
      `Expected 5 fields but got ${parts.length} in expression "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(parts[i], FIELD_CONFIGS[fieldName], fieldName);
  }

  return result;
}

export default parseCron;

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be greater than 0");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatValue = Primitive | Function | Date | RegExp | Map<unknown, unknown> | Set<unknown>;
type NestedObject = { [key: string]: unknown };
type FlattenedObject = { [key: string]: FlatValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || value === undefined) return false;
  if (typeof value !== "object") return false;
  // Treat arrays as plain objects (indices become dot-notation keys)
  if (Array.isArray(value)) return true;
  // Reject built-in complex types — treat them as leaf values
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  seen: WeakSet<object> = new WeakSet(),
  result: FlattenedObject = {}
): FlattenedObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as null | undefined;
    }
    return result;
  }

  if (typeof input !== "object" && typeof input !== "function") {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (!isPlainObject(input)) {
    // Non-plain object (Date, RegExp, Map, Set, Function, class instance, etc.)
    if (prefix !== "") {
      result[prefix] = input as FlatValue;
    }
    return result;
  }

  const obj = input as NestedObject;

  // Guard against circular references — fail safe instead of infinite loop
  if (seen.has(obj)) {
    if (prefix !== "") {
      result[prefix] = "[Circular]";
    }
    return result;
  }
  seen.add(obj);

  const keys = Object.keys(obj); // Own enumerable string-keyed properties only

  // If the object is empty, preserve it as an explicit key with an empty-object marker
  // only when it's a nested value (prefix is set), so the caller gets a useful signal
  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {} as unknown as FlatValue;
    }
    seen.delete(obj);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    // Escape any literal dots in keys to prevent ambiguous round-tripping
    const escapedKey = key.replace(/\./g, "\\.");
    const newPrefix = prefix === "" ? escapedKey : `${prefix}.${escapedKey}`;
    const value = obj[key];

    flattenObject(value, newPrefix, seen, result);
  }

  seen.delete(obj);
  return result;
}

export default flattenObject;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isFinite(capacity) || isNaN(capacity)) {
      throw new TypeError(`LRUCache capacity must be a finite number, got: ${capacity}`);
    }

    this.capacity = Math.max(0, Math.floor(capacity));
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (key === undefined || key === null) {
      return undefined;
    }

    if (!this.cache.has(key)) {
      return undefined;
    }

    // Promote to most-recently-used by re-inserting at end of Map
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (key === undefined || key === null) {
      throw new TypeError(`LRUCache key must be a non-null string, got: ${key}`);
    }

    if (this.capacity === 0) {
      // Zero-capacity cache: store nothing, silently discard
      return;
    }

    if (this.cache.has(key)) {
      // Key already exists — delete so re-insertion moves it to most-recently-used
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Evict the least-recently-used entry (first key in insertion-order Map)
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  get size(): number {
    return this.cache.size;
  }

  has(key: string): boolean {
    if (key === undefined || key === null) {
      return false;
    }
    return this.cache.has(key);
  }

  delete(key: string): boolean {
    if (key === undefined || key === null) {
      return false;
    }
    return this.cache.delete(key);
  }

  clear(): void {
    this.cache.clear();
  }
}

export default LRUCache;

type PlainObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Accept Object.create(null) (proto === null) and plain object literals
  return proto === Object.prototype || proto === null;
}

export default function flattenObject(
  obj: PlainObject,
  prefix = "",
  _seen = new WeakSet<object>()
): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject: expected a plain object, got ${obj === null ? "null" : typeof obj}`
    );
  }

  if (_seen.has(obj)) {
    throw new Error(
      `flattenObject: circular reference detected at key "${prefix}"`
    );
  }

  _seen.add(obj);

  const result: FlatObject = {};

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      // Recurse into non-empty plain objects only.
      // Empty objects {} would vanish if recursed — preserve them as leaf values instead.
      const nested = flattenObject(value, flatKey, _seen);
      for (const nestedKey of Object.keys(nested)) {
        result[nestedKey] = nested[nestedKey];
      }
    } else {
      // Leaf values: primitives, null, arrays, Dates, RegExps,
      // class instances, undefined, and empty plain objects.
      result[flatKey] = value;
    }
  }

  // Remove on exit so the same object reference can appear in sibling
  // branches without triggering a false circular-reference error.
  _seen.delete(obj);

  return result;
}
